INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD1', N'Tai nghe Bluetooth Apple AirPods 4 - Cũ Đẹp', N'Apple Chính hãng', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/i/airpods-4-1_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/i/airpods-4-2_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/i/airpods-4-3_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/i/airpods-4-3-1_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/i/airpods-4-3-2_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/i/airpods-4-3-3_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/i/airpods-4-3-4_1_1.png"]', N'{"Công nghệ âm thanh": {"Công nghệ âm thanh": "Trình điều khiển Apple với độ lệch tương phản cao có thể tùy chỉnh\nBộ khuếch đại với độ lệch tương phản cao có thể tùy chỉnh\nTách Lời Nói\nChế độ Âm Thanh Không Gian Cá Nhân Hóa với tính năng theo dõi chuyển động đầu chủ động\nEQ Thích Ứng H", "Micro": "Có", "Tính năng": "Chống ồn, Điều khiển giọng nói, Xuyên âm, Có mic đàm thoại, Sạc không dây"}, "Khả năng kết nối": {"Bluetooth": "5.3"}, "Thời lượng pin - sạc": {"Dung lượng pin": "Thời gian nghe lên đến 5 giờ với một lần sạc\nThời gian đàm thoại lên đến 4,5 giờ với một lần sạc", "Cổng sạc": "USB-C", "Thời gian sạc": "Hãng không công bố"}, "Điều khiển": {"Phương thức điều khiển": "Cảm ứng chạm"}, "Kích thước & Trọng lượng": {"Kích thước": "Tai nghe: 30.2 x 18.3 x 18.1 mm\nHộp sạc: 46.2 x 50.1 x 21.2 mm", "Trọng lượng": "Tai nghe: 4.3g\nHộp sạc: 32.3g"}, "Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}, "Chống nước": {"Chống nước": "IP54"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD2', N'Tai nghe chụp tai chống ồn Apple AirPods Max 2 2026 | Chính hãng Apple Việt Nam', N'Apple Chính hãng', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_1__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_2__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_3__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_7__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_7_.png"]', N'{"Kích thước & Trọng lượng": {"Kích thước": "168.6 x 187.3 x 83.4 mm", "Trọng lượng": "AirPods Max 2, bao gồm đệm tai: 386,2 gram\nSmart Case: 134,5 gram"}, "Công nghệ âm thanh": {"Công nghệ âm thanh": "Trình điều khiển động do Apple thiết kế\nBộ khuếch đại với độ lệch tương phản cao có thể tùy chỉnh\nChủ Động Khử Tiếng Ồn Âm Thanh Thích Ứng\nChế độ Xuyên Âm\nNhận Biết Cuộc Hội Thoại\nTách Lời Nói\nÂm Lượng Được Cá Nhân Hóa\nGiảm Âm", "Micro": "Tổng cộng chín micrô:\nTám micrô dành cho tính năng Chủ Động Khử Tiếng Ồn\nBa micrô dành cho tính năng nhận diện giọng nói (hai micrô dùng chung với tính năng Chủ Động Khử Tiếng Ồn và một micrô bổ sung)", "Tính năng": "Xuyên âm, Có mic đàm thoại, Chống ồn chủ động ANC", "Cảm biến": "Cảm biến quang học (mỗi bên củ tai)\nCảm biến vị trí (mỗi bên củ tai)\nCảm biến phát hiện hộp (mỗi bên củ tai)\nGia tốc kế (mỗi bên củ tai)\nCon quay hồi chuyển (củ tai bên trái)"}, "Khả năng kết nối": {"Bluetooth": "5.3"}, "Thời lượng pin - sạc": {"Thời lượng sử dụng Pin": "Lên đến 20 giờ với một lần sạc khi bật tính năng Chủ Động Khử Tiếng Ồn", "Cổng sạc": "Cáp Sạc USB-C"}, "Điều khiển": {"Thao tác điều khiển": "Digital Crown\nXoay để điều khiển âm lượng\nNhấn một lần để phát hoặc tạm dừng phương tiện\nNhấn một lần để trả lời cuộc gọi, bật hoặc tắt tiếng\nNhấn một lần để mở điều khiển camera\nNhấn hai lần để kết thúc cuộc gọi\nNhấn hai lần để tua tớ"}, "Tính năng - Tiện ích khác": {"Tính năng khác": "Các tính năng Trợ Năng giúp người khuyết tật tận dụng tối đa AirPods Max mới của mình.\nCác tính năng bao gồm:\nÂm thanh Nghe Trực Tiếp\nMức âm thanh tai nghe\nThích Nghi Tai Nghe"}, "Vi xử lý & đồ họa": {"Chipset": "Chip tai nghe Apple H2 (mỗi bên củ tai)"}, "Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD3', N'Apple AirTag 2', N'Apple Chính hãng', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2_6_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2_7_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2-combo-x4_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2-combo-x4_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2-combo-x4_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2-combo-x4_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2-combo-x4_6_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-airtag-2-combo-x4_7_.png"]', N'{"Vi xử lý & đồ họa": {"Chipset": "Chip U2 (sử dụng công nghệ Ultra Wideband)"}, "Pin & công nghệ sạc": {"Pin": "CR2032"}, "Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}, "Chống nước": {"Chống nước": "IP67"}, "Tiện ích": {"Tính năng khác": "Loa tích hợp phát âm thanh giúp định vị AirTag\nKết nối với ứng dụng Find My trên iPhone\nTheo dõi vị trí đồ vật thông qua ứng dụng trên smartphone"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD4', N'iPad Air 11 inch M4 5G', N'Apple', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/1/01_6_3_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/2/02_4_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/3/03_7_3_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/4/04_6_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/5/05_4_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/6/06_4_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/7/07_4_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/8/08_4_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/9/09_6_3_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/1/010_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/1/01_6_3_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/2/02_4_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/3/03_7_3_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/4/04_6_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/5/05_4_2_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/6/06_4_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/7/07_4_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/8/08_4_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/9/09_6_3_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/1/010_1_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/1/01_6_3_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/2/02_4_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/3/03_7_3_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/4/04_6_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/5/05_4_2_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/6/06_4_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/7/07_4_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/8/08_4_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/9/09_6_3_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/1/010_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/1/01_6_3_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/2/02_4_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/3/03_7_3_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/4/04_6_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/5/05_4_2_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/6/06_4_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/7/07_4_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/8/08_4_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/9/09_6_3_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/0/1/010_1_2.png"]', N'{"Màn hình": {"Kích thước màn hình": "11 inches", "Công nghệ màn hình": "Liquid Retina", "Độ phân giải màn hình": "2360 x 1640 pixel", "Tính năng màn hình": "Màn hình Multi-Touch với công nghệ LED nền và IPS\nĐộ sáng 500 nit\n264 ppi\nDải màu rộng (P3)\nTrue Tone\nLớp phủ chống phản chiếu\nCông nghệ ép kín"}, "Camera sau": {"Camera sau": "12MP, f/1.8, Độ thu phóng kỹ thuật số lên đến 5x\nChụp ảnh toàn cảnh Panorama (lên đến 63MP)", "Quay video": "4K ở tốc độ 24/25/30/60fps\nHD 1080p ở tốc độ 25/30/60fps\nHD 720p ở tốc độ 30 fps", "Tính năng camera": "Tự động lấy nét theo pha Focus Pixels\nHDR thông minh thế hệ 4\nLive Photos\nĐịnh vị ảnh\nTự động chống rung hình ảnh\nChế độ Chụp liên tục\nFlash Re