thế hệ 4\nLive Photos\nĐịnh vị ảnh\nTự động chống rung hình ảnh\nChế độ Chụp liên tục\nFlash Retina với True Tone\nHiệu chỉnh ống kính"}, "Camera trước": {"Camera trước": "12MP Center Stage, ƒ/2.0", "Quay video trước": "Quay video HD 1080p @ 25 fps, 30 fps, hoặc 60 fps"}, "Vi xử lý & đồ họa": {"Chipset": "Chip Apple M4", "GPU": "GPU 9 lõi\nNeural Engine 16 lõi\nCông nghệ dò tia tốc độ cao bằng phần cứng"}, "RAM & lưu trữ": {"Dung lượng RAM": "8 GB", "Bộ nhớ trong": "128 GB"}, "Pin & công nghệ sạc": {"Pin": "Tích hợp pin sạc Li-Po 36,59 watt‑giờ", "Cổng sạc": "USB Type-C"}, "Tính năng khác": {"Hệ điều hành": "iPadOS 26"}, "Bộ xử lý & Đồ họa": {"Loại CPU": "8 lõi với 3 lõi hiệu năng và 5 lõi tiết kiệm điện"}, "Kích thước & Trọng lượng": {"Kích thước": "280,6 x 214,9 x 6,1 mm", "Trọng lượng": "616 g"}, "Thông số khác": {"Tương thích": "Hỗ trợ Apple Pencil Pro\nHỗ trợ Apple Pencil (USB-C)\nHỗ trợ Magic Keyboard cho iPad Air", "Công nghệ - Tiện ích": "FaceTime video\nFaceTime âm thanh\nTrung Tâm Màn Hình iPad gọi đến thiết bị bất kỳ có hỗ trợ\nFaceTime qua Wi-Fi hoặc mạng di động", "Tiện ích khác": "Touch ID", "Công nghệ âm thanh": "Loa stereo ở cạnh trên và cạnh dưới\nHai micrô để gọi, quay video và ghi âm\nÂm Thanh Không Gian"}, "Tiện ích khác": {"Cảm biến vân tay": "Cảm biến vân tay cạnh bên", "Các loại cảm biến": "Cảm biến ánh sáng, Con quay hồi chuyển, Cảm biến áp kế"}, "Cổng kết nối": {"Wi-Fi": "Wi-Fi 7 (802.11be) với 2x2 MIMO5", "Bluetooth": "Bluetooth 6"}}', 'CAT2');
