roduct/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-3_1_2_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-4_1_2_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-5_1_2_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-6_1_2_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-7_1_2_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-8_1_2_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-9_1_2_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-watch-series-9-41mm-4g-_1_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_13__6_112.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-3_1_2_2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-4_1_2_2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-5_1_2_2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-6_1_2_2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-7_1_2_2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-8_1_2_2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/n/vn_apple_watch_series_9_cell_41mm_silver_aluminum_storm_blue_sport_band_pdp_image_position-9_1_2_2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/p/apple-watch-series-9-41mm-4g-_1_2.png"]', N'{"Màn hình": {"Công nghệ màn hình": "Retina", "Kích thước màn hình": "1.6 inch", "Độ phân giải": "352 x 430 Pixel"}, "Thiết kế": {"Chất liệu mặt kính": "Kính cường lực", "Chất liệu viền": "Nhôm", "Đường kính mặt": "41 mm", "Thiết kế": "Mặt vuông", "Trọng lượng": "32.1 gram"}, "Dây đeo": {"Chất liệu dây": "Cao Su", "Kích thước cổ tay phù hợp": "130-180mm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua eSim", "Kháng nước": "5 ATM (đi mưa, bơi ở vùng nước nông)\nĐạt chuẩn chống bụi IP6X", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Cảm biến nhiệt độ, Phát hiện té ngã, Cảnh báo nhịp tim bất thường, Đo điện tâm đồ", "Thông báo": "Cuộc gọi\nTin nhắn", "Tiện ích khác": "Nghe gọi qua eSim, Có định vị GPS, Cài ứng dụng, Phát nhạc trên đồng hồ, Chế độ luyện tập, Hiển thị thông báo điện thoại, Màn hình luôn hiển thị, Tùy chỉnh mặt đồng hồ, Nghe gọi trên đồng hồ, Điều khiển chơi nhạc, Kết nối tai nghe, Nhận thông báo cuộc gọi, Bấm giờ, Báo thức, Tìm điện thoại, Xem bản đồ, Nghe gọi qua Bluetooth", "Tính năng đặc biệt": "Tìm iPhone\nTrợ lý ảo Siri\nĐiều khiển Homepod\nTính năng Double Tap\nGọi khẩn cấp\nThanh toán với Apple Pay"}, "Kích thước & Trọng lượng": {"Kích thước": "41 x 35 x 10.7 mm"}, "Cấu hình": {"Kết nối": "Bluetooth 5.3, GPS, Wi-Fi 4 802.11n", "CPU": "S9 SiP", "Bộ nhớ trong": "64GB", "Hệ điều hành": "WatchOS", "Tương thích": "iOS", "Ứng dụng kết nối": "Watch"}, "Pin": {"Thời lượng pin": "Chế độ thông minh: 18 giờ\nChế độ tiết kiệm pin: 36 giờ", "Cổng sạc": "Không dây"}, "Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}}', 'CAT4');
