INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD78', N'Bút cảm ứng iPad Baseus Smooth Writing 3 Wired Charging Stylus Active Wireless', N'Baseus', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115727.392.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-airpods-pro-3-ravaka-breeds-xanh-duong_40_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115813.031.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115805.200.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115825.860.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115832.566.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115819.549.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t120010.125.png"]', N'{"Pin & công nghệ sạc": {"Pin": "Thời lượng sử dụng: lên đến 17 giờ\nDung lượng pin: 140mAh\nChip tiêu thụ điện năng thấp"}, "Kích thước & Trọng lượng": {"Kích thước": "Chiều dài: 165 mm\nĐường kính: 9 mm", "Trọng lượng": "15.5g"}, "Thông tin hãng": {"Hãng sản xuất": "Baseus"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Thân bút: Hợp kim nhôm\nĐầu bút: POM (Polyoxymethylene)"}, "Thông số kỹ thuật": {"Cổng sạc ra": "Sạc có dây qua cổng Type-C"}, "Thông số khác": {"Tiện ích": "Công nghệ chống nhiễu LDS\nĐầu bút mạ vàng tăng độ ổn định tín hiệu\nHỗ trợ 32 chức năng tùy chỉnh chỉ với 1 lần chạm\nNút bấm vật lý tích hợp trên thân bút\nTự động bật khi cầm lên (Auto Wake)\nTích hợp AI và cảm biến lực nhấn chính xác", "Tương thích": "Nắp chống bụi tích hợp cho cổng sạc\nĐèn LED hiển thị trạng thái hoạt động\nCác chức năng hỗ trợ gồm: Về màn hình chính (Home), Nguồn (Power), Điều chỉnh độ sáng, Ứng dụng gần đây, Tăng/giảm âm lượng, Chuyển trang trước/sau, Tắt tiếng, Tìm kiếm, Chụp ảnh, Chụp màn hình nhanh, Chỉnh sửa screenshot, Palm rejection (chống chạm nhầm)"}}', 'CAT1');
