INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD84', N'Camera AI 360 độ 4MP Vantech AI-V2010C', N'Vantech', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ai-vantech-ai-v2010c_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ai-vantech-ai-v2010c_1_.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ai-vantech-ai-v2010c_3_.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ai-vantech-ai-v2010c_2_.jpg"]', N'{"Thông số chính": {"Dòng camera": "Camera trong nhà", "Độ phân giải": "4MP", "Góc nhìn": "360 độ", "Góc xoay": "Xoay ngang 355°\nXoay dọc 90°", "Cảm biến ảnh": "Ống kính 3.6mm", "Tầm nhìn": "Quan sát ngày đêm ở khoảng cách tối đa 10-20M"}, "Lưu trữ và kết nối": {"Kết nối": "Wifi không dây chuẩn IEEE 802.11b/g", "Bộ nhớ": "Hỗ trợ thẻ nhớ", "Chuẩn lưu trữ": "Thẻ nhớ 128GB", "Ứng dụng hỗ trợ": "Vantech Pro", "Tương thích": "Android, iOS", "Nguồn điện": "5V – 2A"}, "Tính năng và tiện ích": {"Tính năng": "Nhận ngay cuộc gọi từ Server Cloud khi có tín hiệu báo động\nHỗ trợ 3 chế độ thông báo báo động: Khi ở nhà, khi ra ngoài và tin nhắn\nHỗ trợ AI – Phát hiện theo dõi con ngườ\nÂm báo động có thể thay bằng giọng nói từ chính người dùng tự ghi âm"}, "Thông tin hãng": {"Hãng sản xuất": "Vantech"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD85', N'Camera AI 360 độ 2MP Vantech V2010', N'Vantech', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ai-vantech-v2010.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ai-v1310.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/4/2/4297_camera-vantech-ai-v2010.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/a/gallery-ai-camera-1a.jpg"]', N'{"Thông số chính": {"Dòng camera": "Camera trong nhà", "Độ phân giải": "2MP", "Góc nhìn": "360 độ", "Góc xoay": "Xoay ngang 355°\nXoay dọc 90°", "Cảm biến ảnh": "Ống kính 3.6mm", "Tầm nhìn": "Quan sát ngày đêm ở khoảng cách tối đa 10-20M"}, "Lưu trữ và kết nối": {"Kết nối": "Wifi không dây chuẩn IEEE 802.11b/g", "Bộ nhớ": "Hỗ trợ thẻ nhớ", "Chuẩn lưu trữ": "Thẻ nhớ 128GB", "Ứng dụng hỗ trợ": "AI_V3", "Tương thích": "Android, iOS", "Nguồn điện": "5V – 2A"}, "Tính năng và tiện ích": {"Tính năng": "Nhận ngay cuộc gọi từ Server Cloud khi có tín hiệu báo động\nHỗ trợ 3 chế độ thông báo báo động: Khi ở nhà, khi ra ngoài và tin nhắn\nHỗ trợ AI – Phát hiện theo dõi con ngườ\nÂm báo động có thể thay bằng giọng nói từ chính người dùng tự ghi âm\nQuay ban đêm có màu", "Bảo mật": "WEP & WPA & WPA2 Encryption"}, "Thông tin hãng": {"Hãng sản xuất": "Vantech"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD86', N'Camera AI 3MP Vantech VP-2200IP', N'Vantech', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/p/vp-2200ip.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/v/p/vp-2200ip1_1.jpg"]', N'{"Thông số chính": {"Dòng camera": "Camera trong nhà", "Độ phân giải": "3MP", "Góc xoay": "Cố định", "Cảm biến ảnh": "1/2.8\" SONY chipset", "Tầm nhìn": "40 mét"}, "Lưu trữ và kết nối": {"Kết nối": "Wifi không dây chuẩn IEEE 802.11b/g", "Bộ nhớ": "Hỗ trợ thẻ nhớ", "Ứng dụng hỗ trợ": "AI_V3", "Tương thích": "Android, iOS", "Nguồn điện": "5V – 2A"}, "Tính năng và tiện ích": {"Tính năng": "Quay ban đêm có màu\nChế độ hồng ngoại thông minh (Smart infrared)\nChức năng phát hiện chuyển động Motion Detect.\nChức năng bảo vệ vùng riêng tư Privacy Masking.", "Bảo mật": "WEP & WPA & WPA2 Encryption", "Kháng nước": "IP67"}, "Thông tin hãng": {"Hãng sản xuất": "Vantech"}}', 'CAT1');
