INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD192', N'Sạc Cuktech 3C1A 140W (CN) AD1404U', N'Cuktech', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-3c1a-140w-cn-ad1404u_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-3c1a-140w-cn-ad1404u_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-3c1a-140w-cn-ad1404u_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-3c1a-140w-cn-ad1404u_6_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-3c1a-140w-cn-ad1404u_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-3c1a-140w-cn-ad1404u_7_.png"]', N'{"Tổng quan": {"Công suất sạc": "140W", "Sử dụng tối đa": "4 thiết bị", "Đầu vào": "1 x AC", "Đầu ra": "3 x USB-C\n1 x USB-A", "Nguồn vào": "110–240V, 50/60Hz, 2A", "Nguồn ra": "Cổng ra đơn\n+ USB-A: 33W (5–11V/3A, UFCS fast charging, PPS)\n+ Type-C3: 33W (5–11V/3A, PPS)\n+ Type-C2: 140W (28V/5A, MacBook Pro), 120W (20V/6A, điện thoại Xiaomi), 100W (20V/5A, laptop)\n+ Type-C1: 140W (28V/5A, MacBook Pro), 120W (20V/6A, điện thoại Xiaomi), 100W (20V/5A, laptop)\nCổng ra kép\n+ Type-C2 + Type-C1: 33W (điện thoại) + 100W (laptop)\n+ Type-C2 + Type-C1: 67W (điện thoại Xiaomi) + 67W/45W (điện thoại Samsung)\n+ Type-C3/USB-A + Type-C1/C2: 33W (điện thoại) + 100W (laptop)\n+ Type-C2 + Type-C1: 45W (laptop) + 65W (laptop)\nCổng ra ba\nType-C3/USB-A + Type-C2 + Type-C1:\n+ USB-A: 5V 1.5A\n+ Type-C3: 5V 1.5A\n+ Type-C2: 45W (laptop)\n+ Type-C1: 65W (laptop)\nType-C3/USB-A + Type-C2 + Type-C1:\n+ Type-C3/USB-A: 33W (điện thoại)\n+ Type-C2: 33W (điện thoại)\n+ Type-C1: 45W (laptop) / 67W (điện thoại Xiaomi) / 45W (điện thoại Samsung)\nType-C3/USB-A + Type-C2 + Type-C1:\n+ USB-A: 5V 1.5A\n+ Type-C3: 5V 1.5A\n+ Type-C2: 100W (laptop) / 67W (điện thoại Xiaomi)\n+ Type-C1: 33W (điện thoại)\nCổng ra bốn\nType-C3 + USB-A + Type-C2 + Type-C1:\n+ USB-A + Type-C3: tổng 5V 1.5A\n+ Type-C2: 45W (laptop)\n+ Type-C1: 65W (laptop)\nType-C3 + USB-A + Type-C2 + Type-C1:\n+ USB-A: 5V 1.5A\n+ Type-C3: 5V 1.5A\n+ Type-C2: 33W (điện thoại)\n+ Type-C1: 65W (điện thoại Xiaomi)\nType-C3 + USB-A + Type-C2 + Type-C1:\n+ USB-A: 5V 1.5A\n+ Type-C3: 5V 1.5A\n+ Type-C2: 45W (laptop)\n+ Type-C1: 33W (điện thoại)"}, "Công nghệ và tiện ích": {"Tiện ích": "Sạc nhanh\nThiết kế gấp gọn\nChip GaN thế hệ thứ 3\nKiến trúc PFC+LLC\nThiết kế lưới tản nhiệt\nKeo tản nhiệt hiệu suất cao, dẫn nhiệt tốt\nIntelligent Power Regulation\nBảo vệ quá áp\nBảo vệ quá dòng đầu vào\nBảo vệ quá dòng đầu ra\nNhiễu gợn sóng thấp\nBảo vệ ngắn mạch\nBảo vệ quá nhiệt\nNhiễu điện từ thấp\nChống tĩnh điện", "Công nghệ/Đạt chứng nhận": "PD3.1, PPS2.0, QC, Mi Turbo 120W, UFCS, Adapt Charge (tự động điều chỉnh công suất)"}, "Thiết kế và trọng lượng": {"Kích thước": "7.99 x 6.5 x 3.2 cm", "Trọng lượng": "~250 g"}, "Thông tin hãng": {"Hãng sản xuất": "Cuktech"}}', 'CAT1');
