INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD198', N'Sạc Cuktech GAN 2C1A 65W kèm cáp C-C Dài 1.5M (CN) AD653C', N'Cuktech', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-gan-2c1a-65w-kem-cap-c-c-1-5m-ad653c_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/_/k_m_c_p_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/_/k_m_c_p.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-gan-2c1a-65w-kem-cap-c-c-1-5m-ad653c_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-gan-2c1a-65w-kem-cap-c-c-1-5m-ad653c_6_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-gan-2c1a-65w-kem-cap-c-c-1-5m-ad653c_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-gan-2c1a-65w-kem-cap-c-c-1-5m-ad653c_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/u/cu-sac-cuktech-gan-2c1a-65w-kem-cap-c-c-1-5m-ad653c_2_.png"]', N'{"Tổng quan": {"Công suất sạc": "65W", "Sử dụng tối đa": "Sạc đồng thời 3 thiết bị", "Đầu vào": "2 x USB-C\n1 x USB-A", "Nguồn vào": "100-240V 50/60Hz 1.8A", "Nguồn ra": "Type-C1: 5V=2A, 5V=3A, 9V=3A, 11V=4A, 12V=3A, 15V=3A, 20V=3.25A 65W Max\nType-C2: 5V=2A, 5V=3A, 9V=3A, 11V=3A, 12V=2.5A 33W Max\nUSB-A: 5V=2A, 5V=3A, 9V=2A, 10V=2.25A, 12V=1.5A 22.5W (SCP)/ 18W Max (QC)\nType-C1+Type-C2: 45W + 20W\nType-C1+USB-A: 45W + 18W\nType-C2+USB-A: 5V=4A 20W Max\nType-C1+(Type-C2+USB-A): 45W + (5V=3A) Max"}, "Công nghệ và tiện ích": {"Tiện ích": "Sạc siêu nhanh\nThiết kế gấp gọn\nChế độ dòng điện thấp thông minh\nBảo vệ quá áp\nBảo vệ quá áp dòng đầu vào\nBảo vệ quá dòng đầu ra\nNhiễu gợn sóng thấp\nBảo vệ ngắn mạch\nBảo vệ quá nhiệt\nNhiễu điện từ thấp\nChống tĩnh điện\nCó thể gập chân sạc", "Công nghệ/Đạt chứng nhận": "Công nghệ GaN III\nTương thích phổ biến với QC, SCP"}, "Thiết kế và trọng lượng": {"Chiều d