INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD222', N'Đèn flash chụp ảnh Ulanzi SL03', N'Ulanzi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/s/s/ssss_2_152.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/s/as01_6__17.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/s/as01_4__18.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/s/as01_5__18.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/s/as01_3__26.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/s/as01_2__25.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/s/as01_1__24.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/a/s/as01_27.png"]', N'{"Thông tin hãng": {"Hãng sản xuất": "Ulanzi"}, "Flash": {"Đèn Flash": "Độ chuẩn sáng: GN8\nChỉ số hoàn màu (CRI): 95\nNhiệt độ màu đèn flash: 6500K ± 8%\nNhiệt độ màu ánh sáng luôn bật: 5600K\nCông suất: 1W\nCông suất điều chỉnh: 4 mức\nChế độ đèn flash: Có\nChế độ lấp đầy ánh sáng luôn bật: Không"}, "Pin & Sạc": {"Pin": "300mAh, 3.7V", "Cổng sạc": "Type-C\nThời gian sạc khoảng 1 giờ (5V/1A)"}, "Kích thước & Trọng lượng": {"Trọng lượng": "36 g"}}', 'CAT8');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD223', N'Dịch vụ gia hạn bảo hành Applecare+ For iMac (M4)', N'Apple Chính hãng', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/i/dich-vu-apple-care-plus-imac-m4.png"]', N'{"Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}, "Thông số khác": {"Áp dụng": "iMac M4", "Thời hạn": "Gia hạn thêm 2 năm bảo hành chính hãng (tổng 3 năm)", "Điều kiện": "Thiết bị mới kích hoạt trong vòng 5 ngày tính từ thời điểm trên hóa đơn (có thể mua từ hệ thống CellphoneS hoặc các hệ thống bán lẻ khác)\nCung cấp được hoá đơn mua hàng (đối với thiết bị mua từ hệ thống bán lẻ khác)\nThiết bị nguyên vẹn chưa xảy ra hư hỏng, cấn móp, tai nạn\nHàng chính hãng Apple\nGiá sản phẩm đã bao gồm VAT", "Ưu đãi": "Bảo hành rơi vỡ, rớt nước không giới hạn với mức phí thấp\nBảo hành phần cứng tất cả các lỗi từ NSX (miễn phí)\nBảo hành cả phụ kiện đi kèm máy (miễn phí)\nƯu tiên hỗ trợ kỹ thuật qua tổng đài 24/7"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD224', N'Dịch vụ gia hạn bảo hành Applecare+ cho iPad Air 11 inch (M4)', N'Apple Chính hãng', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2024-07-01t171709.025_1_1_1_1.png"]', N'{"Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}, "Thông số khác": {"Áp dụng": "iPad Air 11 inch (M4)", "Thời hạn": "Gia hạn thêm 1 năm bảo hành chính hãng (tổng 2 năm)", "Điều kiện": "Thiết bị mới kích hoạt trong vòng 5 ngày tính từ thời điểm trên hóa đơn (có thể mua từ hệ thống CellphoneS hoặc các hệ thống bán lẻ khác)\nCung cấp được hoá đơn mua hàng (đối với thiết bị mua từ hệ thống bán lẻ khác)\nThiết bị nguyên vẹn chưa xảy ra hư hỏng, cấn móp, tai nạn\nHàng chính hãng Apple\nGiá sản phẩm đã bao gồm VAT", "Ưu đãi": "Bảo hành rơi vỡ, rớt nước không giới hạn với mức phí thấp\nĐược thay pin nếu dung lượng còn lại ít hơn 80% so với dung lượng ban đầu (miễn phí)\nBảo hành phần cứng tất cả các lỗi từ NSX (miễn phí)\nBảo hành cả phụ kiện đi kèm máy (miễn phí)\nƯu tiên hỗ trợ kỹ thuật qua tổng đài 24/7"}}', 'CAT1');
