INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD288', N'Flycam E88 Max', N'Hãng khác', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-e88-max.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-e88-max_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-e88-max_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-e88-max_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-e88-max_2_.png"]', N'{"Phi cơ": {"Kích thước": "25 x 25 x 5.5cm (Mở ra)\n12.5 x 8.1 x 5.3cm (Gấp gọn)", "Độ cao cất cánh tối đa": "100m", "Thời gian bay tối đa": "Khoảng 15 phút", "Khoảng cách bay tối đa": "500m"}, "Thông số khác": {"Ống kính": "Độ phân giải: HD", "Thời gian sạc": "60 phút", "Tiện ích": "Con quay hồi chuyển: 6 trục\nKênh: 4CH\nĐộng cơ không chổi than"}, "Camera": {"Độ phân giải video": "HD"}, "Truyền Video": {"Hệ thống truyền video": "WiFi FPV", "Tần số hoạt động": "2.4G"}, "Ắc quy": {"Dung lượng Pin": "2200mAH", "Điện áp": "3.7V"}, "Thông tin hãng": {"Hãng sản xuất": "Hãng khác"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Nhựa ABS & Linh kiện điện tử"}}', 'CAT10');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD289', N'Flycam i9 max', N'Hãng khác', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-i9-max.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-i9-max_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-i9-max_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-i9-max_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-i9-max_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-i9-max_6_.png"]', N'{"Phi cơ": {"Kích thước": "Mở cánh: 165 x 188 x 59 mm\nGấp: 142 x 84 x 57mm", "Trọng lượng": "249 gam", "Độ cao cất cánh tối đa": "500m", "Thời gian bay tối đa": "25 – 30 phút", "Khoảng cách bay tối đa": "3000m", "Định vị": "GPS/GLONASS"}, "Thông số khác": {"Ống kính": "Độ phân giải hình ảnh 4K", "Thời gian sạc": "3 – 4 tiếng", "Tiện ích": "App điều khiển Enjoy – Fly2\nĐộng cơ không chổi than"}, "Camera": {"Độ phân giải video": "4K"}, "Bộ phận chống rung": {"Chống rung": "3 trục"}, "Truyền Video": {"Tần số hoạt động": "2.4 th FPV"}, "Ắc quy": {"Dung lượng Pin": "2100 mAh", "Điện áp": "8.8 V (Min 7.7 V) – 2A"}, "Bộ sạc": {"Đầu vào": "DC 5V – 2A", "Đầu ra": "DC 4.4 V – 2A"}, "Thông tin hãng": {"Hãng sản xuất": "Hãng khác"}}', 'CAT10');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD290', N'Flycam Xiaomi FIMI A3', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-a3_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-a3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-a3_2_.png"]', N'{"Pin & công nghệ sạc": {"Pin": "Pin Lipo"}, "Phi cơ": {"Kích thước": "285 x 229 x 69mm\nKích thước đường chéo 323mm", "Trọng lượng": "560g", "Tốc độ tối đa": "Tốc độ tăng dần tối đa: 6 m / s\nTốc độ tối đa giảm dần: 5 m / s\nTốc độ bay tối đa: 18 m / s", "Độ cao cất cánh tối đa": "500 m", "Thời gian bay tối đa": "25 phút", "Khoảng cách bay tối đa": "khoảng 1km", "Chống tốc độ gió tối đa": "≤ 4", "Định vị": "GPS + GLONASS", "Phạm vi chính xác khi lượn": "Khi định vị GPS đang hoạt động, Dọc: ± 0,5 m & Ngang: ± 1,5 m"}, "Camera": {"Cảm biến": "1 / 3.2 “CMOS", "ISO": "100 – 3200 cho video; 100 – 1600 cho ảnh", "Tốc độ màn trập": "4 ~ 1/8000 s", "Định dạng ảnh": "JPG", "Độ phân giải video": "1920×1080 30 fps / 1920×1080 25 fps\nDVR: 1920×1080 30 fps / 1920×1080 25 fps", "Định dạng video": "MP4", "Tốc độ bit video tối đa": "60Mb / giây", "Tệp tin hỗ trợ": "FAT32 / exFAT"}, "Thông số khác": {"Ống kính": "FOV 80 °\nKhẩu độ: f2.0\nKhoảng cách tiêu cự: 3,54 mm\nKhoảng cách tiêu cự tương đương: 27mm\nĐộ phân giải ảnh: 8M 3264 * 2448", "Tiện ích": "Chế độ không đầu\nChế độ bay theo quỹ đạo vạch sẵn\nChế độ theo dõi follow me bay theo đối tượng\nChế độ return one key – tự động quay trở về khi máy bay mất tín hiệu hoặc kết nối sóng yếu hay sắp hết pin\nChế độ tự động giữ cân bằng trên không"}, "Bộ phận chống rung": {"Chống rung": "2-aixs cơ khí và 3-aixs điện tử gimbal", "Phạm vi cơ khí": "0 ° ~ -90 ° Góc dốc"}, "Truyền Video": {"Tần số hoạt động": "2.4-2.483GHz\nPin 5.725-5.850 GHz (40CH)"}, "Ắc quy": {"Dung lượng Pin": "2000 mAh", "Điện áp": "11.1V"}, "Bộ sạc": {"Đầu vào": "Micro USB"}, "Trung tâm sạc pin": {"Đầu vào": "100-240V ~ 50 / 60Hz 0.3A", "Đầu ra": "14V 0.8A", "Công suất": "11.2W"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}, "Tiện ích": {"Tính năng khác": "Độ phân giải màn hình remote 480 x 272\nKích thước màn hình 4,3 inch"}}', 'CAT10');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD291', N'Flycam Xiaomi Fimi X8 Mini', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-x8-mini_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-x8-mini_2__2.png"]', N'{"Phi cơ": {"Kích thước": "145 x 85 x 56mm (gấp lại)\n200 x 145 x 56 (mở ra)", "Trọng lượng": "258g", "Tốc độ tối đa": "Tốc độ bay tối đa: 16m / s", "Thời gian bay tối đa": "30 phút", "Khoảng cách bay tối đa": "8000m", "Định vị": "GPS + GLONASS + BEIDUO", "Lưu trữ": "Micro SD (U3 trở lên) 8 – 256GB"}, "Camera": {"Cảm biến": "1 / 2.6 “CMOS, 12M pixel", "Chế độ chụp ảnh tĩnh": "Chụp toàn cảnh panorama\nChụp ảnh tua nhanh thời gian timelapse\nChế độ cảnh đêm", "Định dạng ảnh": "PG; JPG + DNG", "Độ phân giải video": "3840×2160 30/25/24 khung hình / giây (HDR)", "Định dạng video": "MP4", "Tốc độ bit video tối đa": "100Mbps", "Zoom kỹ thuật số": "3x"}, "Thông số khác": {"Ống kính": "Ống kính: FOV 80 °\nKhẩu độ camera: f2.0\nKhoảng cách tiêu cự máy ảnh: 3,54mm\nKhoảng cách tiêu cự tương đương: 26mm", "Tiện ích": "Tính năng Follow me\nLập kế hoạch lộ trình\nTự động bay về khi pin yếu/hoặc mất tín hiệu\nBay quanh 1 điểm cố định\nBay thẳng đứng lên cao\nThiết lập vùng cấm bay\nCảnh báo gió mạnh\nLivestreams trực tiếp lên mạng xã hội"}, "Bộ phận chống rung": {"Chống rung": "Gimbal: 3 trục"}, "Truyền Video": {"Tần số hoạt động": "5.725-5.850 GHz"}, "Ắc quy": {"Dung lượng Pin": "3500mAh"}, "Bộ sạc": {"Đầu vào": "9V / 3A"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}}', 'CAT10');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD292', N'Flycam Xiaomi Fimi X8 SE 2022 Fullbox', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-x8-se-2022-fullbox_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-x8-se-2022-fullbox.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-x8-se-2022-fullbox_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-x8-se-2022-fullbox_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-x8-se-2022-fullbox_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-fimi-x8-se-2022-fullbox_4_.png"]', N'{"Phi cơ": {"Kích thước": "204 x 106 x 72,6 mm (gấp lại)\nKích thước đường chéo: 372mm", "Trọng lượng": "768g", "Tốc độ tối đa": "Tốc độ tăng dần tối đa: 5m/giây\nTốc độ giảm dần tối đa: 4m/giây\nTốc độ bay tối đa: 18m/giây", "Độ cao cất cánh tối đa": "800m", "Thời gian bay tối đa": "35 phút", "Khoảng cách bay tối đa": "10Km", "Chống tốc độ gió tối đa": "Kháng gió cấp 8", "Định vị": "GPS+GLONASS+BEIDOU", "Phạm vi chính xác khi lượn": "± 0,1m (Trong siêu âm phạm vi phát hiện)\n0,5m (khi Định vị GPS đang hoạt động)\nNgang 1,5m", "Lưu trữ": "(tối đa 256G) Đề nghị sử dụng thẻ U3 Micro SD, sử dụng với thẻ SD (Sản phẩm không chứa thẻ SD)"}, "Camera": {"Cảm biến": "1/2 inch CMOS với 48 triệu điểm ảnh, 12M", "Chế độ chụp ảnh tĩnh": "Toàn cảnh\nChụp Cảnh Đêm", "Độ phân giải video": "4K (HDR)", "Zoom kỹ thuật số": "3x"}, "Thông số khác": {"Ống kính": "Khẩu độ lớn F1.6\nĐộ phân giải Camera 48MP (HDR)", "Tiện ích": "Bộ điều khiển từ xa có màn hình tích hợp\nThiết bị có thể mang và thả trọng tải lên tới 200g\nLập kế hoạch chuyến bay\nTheo dõi mục tiêu của bạn\nChuyến bay tròn\nChế độ SAR (Tìm kiếm và Cứu nạn)\nHạ cánh chính xác\nChia sẻ video trực tiếp"}, "Bộ phận chống rung": {"Chống rung": "Gimbal cơ học 3 trục"}, "Truyền Video": {"Tần số hoạt động": "2.400G-2.4835GHz"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}, "Tiện ích": {"Tính năng khác": "Chống mưa\nTrở về điểm xuất phát\nThiết kế Hệ thống IMU kép\nTheo dõi thời gian thực bằng GPS\nBảo vệ: không bay, cách thức\nCảnh báo pin yếu – Quay về\nCảnh báo gió\nCảnh báo sức mạnh quá tải\nCó thể truyền giọng nói hoặc âm thanh từ xa"}}', 'CAT10');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD293', N'Flycam Xiaomi Mi Drone 4K', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-mi-drone-4k_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-mi-drone-4k_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-mi-drone-4k.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-mi-drone-4k_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/l/flycam-xiaomi-mi-drone-4k_5_.png"]', N'{"Pin & công nghệ sạc": {"Pin": "LiPo"}, "Phi cơ": {"Kích thước": "38,00 x 45,50 x 17,00 cm", "Trọng lượng": "4.5800 kg", "Độ cao cất cánh tối đa": "3000m", "Thời gian bay tối đa": "Khoảng 27 phút", "Khoảng cách bay tối đa": "4km", "Định vị": "GLONASS, GPS"}, "Thông số khác": {"Ống kính": "Camera 4K UHD", "Tiện ích": "Gyro 6 trục\nChuyến bay chỉ cần Chạm để bay\nChuyến bay vòng tròn quanh 1 điểm\nQuy hoạch tuyến đường\nMột phím tự động cất / trả / hạ cánh, giám sát mức pin thời gian thực và cảnh báo trở về điện áp thấp"}, "Camera": {"Độ phân giải video": "4K"}, "Bộ phận chống rung": {"Chống rung": "Gimbal 3 trục"}, "Cảm biến": {"Loại cảm biến": "Dòng quang, Sonar"}, "Truyền Video": {"Tần số hoạt động": "5GHz"}, "Ắc quy": {"Dung lượng Pin": "5100mAh", "Điện áp": "15,2V", "Thời gian sạc": "Khoảng 3,5 tiếng"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Sợi carbon, Linh kiện điện tử, PC"}, "Tiện ích": {"Tính năng khác": "Phiên bản không chổi than\nĐiều khiển radio\nĐiều khiển ứng dụng WiFi, WiFi FPV"}}', 'CAT10');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD294', N'Gậy Selfie Stick Wiwu Magnetic SE014', N'Wiwu', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/a/gay-chup-anh-selfie-stick-wiwu-magnetic-se014_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/a/gay-chup-anh-selfie-stick-wiwu-magnetic-se014_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/a/gay-chup-anh-selfie-stick-wiwu-magnetic-se014_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/a/gay-chup-anh-selfie-stick-wiwu-magnetic-se014_7_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/a/gay-chup-anh-selfie-stick-wiwu-magnetic-se014_6_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/a/gay-chup-anh-selfie-stick-wiwu-magnetic-se014_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/a/gay-chup-anh-selfie-stick-wiwu-magnetic-se014_8_.png"]', N'{"Kích thước & Trọng lượng": {"Kích thước": "Gập: 74 x 71 x 220 mm\nKéo giãn: 300 x 300 x 1240 mm"}, "Thông tin hãng": {"Hãng sản xuất": "Wiwu"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Hợp kim nhôm + ABS"}, "Tiện ích": {"Tính năng khác": "Bluetooth Selfie\nHỗ trợ chụp ngang dọc\nKhả năng xoay xoay 360 độ\nKhả năng chịu lực tối đa 500g"}, "Thông số khác": {"Tiện ích": "Tích hợp giá đỡ Magsafe ổn định, lực hút mạnh\nTay cầm cân bằng chống trọng lực", "Tương thích": "iPhone 12 /13/14/15/16 (iPhone 11 trở xuống, điện thoại Android, không có ốp lưng MagSafe) bằng cách sử dụng vòng kim loại dính 3M vô giá có trong gói sản phẩm."}}', 'CAT1');
