INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD362', N'Kính thông minh Rokid AI Glasses Style RV203', N'Rokid', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203_7_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203_8_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/k/i/kinh-thong-minh-rokid-ai-glasses-style-rv203_9_.png"]', N'{"Thông tin hãng": {"Hãng sản xuất": "Rokid"}, "Camera và hình ảnh": {"Camera": "12MP Sony IMX681 (3024 x 4032)\nChất lượng hình ảnh tối đa 4K\nChất lượng video tối đa: 3K / 30fps\nKhẩu độ F 2.25\nTiêu cự 1.9 m\nGóc nghiêng 3°\nCamera: 109° (D)\nHiển thị AR: 30°", "Âm thanh": "Hệ thống 4 micro định hướng\nLoa kép AAC 0920", "Bộ nhớ": "2GB RAM / 32GB ROM"}, "Pin và sạc": {"Pin": "210 mAh\n6 giờ phát nhạc liên tục\n5 giờ cuộc gọi liên tục\n2 giờ dịch thuật liên tục\n45 phút quay video liên tục"}, "Tiện ích và cảm biến": {"Tiện ích": "Hệ thống xử lý: Snapdragon AR1 Gen 1\nKết nối App Hi Rokid\nĐiều khiển cử chỉ đầu\nPhím tắt AI\nChụp ảnh bằng một nút nhấn\nĐèn cảnh báo quyền riêng tư\nTích hợp ChatGPT thông minh", "Kết nối": "Wi-Fi 6\nBluetooth 5.3"}, "Thiết kế và trọng lượng": {"Kích thước": "Kích thước vật lý: Ngang: 149 mm / Dài: 157 mm / Cầu mũi: 21 mm\nKích thước tròng: Rộng: 53 mm / Cao: 50.6 mm", "Trọng lượng": "38.5 g", "Chất liệu": "Bản lề hợp kim titan\nKhung nhựaTR90"}}', 'CAT1');
