INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD520', N'MacBook Pro 14 M5 10CPU 10GPU 32GB 1TB Nano Sạc 96W | Chính hãng Apple Việt Nam', N'Apple', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_2__11_27_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_3__9_19_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_4__9_18_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_5__11_2_4_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_6__6_5_4_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_7__6_2_4_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_8__10_3_4_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_9__10_14_2_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_10__6_2_4_2_1.png"]', N'{"Bộ xử lý & Đồ họa": {"Chip AI": "Apple Intelligence", "Loại card đồ họa": "GPU 10 lõi\nNeural Engine 16 lõi", "Loại CPU": "Chip Apple M5 10 lõi với 4 lõi hiệu năng và 6 lõi tiết kiệm điện"}, "Bộ nhớ RAM, Ổ cứng": {"Dung lượng RAM": "32GB", "Ổ cứng": "1TB"}, "Màn hình": {"Tần số quét": "120 Hz", "Kích thước màn hình": "14.2 inches", "Công nghệ màn hình": "Màn hình Nano-texture\nLiquid Retina XDR\nTỷ lệ tương phản 1.000.000:1\nĐộ sáng XDR 1.000 nit toàn màn hình, độ sáng đỉnh 1.600 nit (chỉ HDR)\nĐộ sáng SDR 1.000 nit (ngoài trời)\n1 tỷ màu\nDải màu rộng (P3)\nCông nghệ True Tone", "Độ phân giải màn hình": "3024 x 1964 pixels"}, "Âm thanh": {"Công nghệ âm thanh": "Hệ thống âm thanh sáu loa có độ trung thực cao với loa trầm khử lực\nÂm thanh stereo rộng\nHỗ trợ Âm Thanh Không Gian khi phát nhạc hoặc video với Dolby Atmos trên loa tích hợp\nDãy ba micrô chất lượng chuẩn studio với tỷ lệ tín hiệu – nhiễu cao"}, "Kích thước & Trọng lượng": {"Chất liệu": "Vỏ kim loại", "Chất liệu vỏ màn hình": "Nhôm", "Chất liệu vỏ trên": "Nhôm", "Chất liệu vỏ dưới": "Nhôm", "Kích thước": "1.55 x 31.26 x 22.12 cm (Cao x Rộng x Dài)", "Trọng lượng": "1.55 kg"}, "Tiện ích khác": {"Tính năng đặc biệt": "Viền màn hình siêu mỏng, Wi-Fi 6, Bảo mật vân tay"}, "Tính năng khác": {"Loại đèn bàn phím": "Bàn phím Magic Keyboard có đèn nền\nBàn di chuột Force Touch để điều khiển con trỏ chính xác và cảm ứng lực; hỗ trợ Bấm Mạnh, bộ tăng tốc, vẽ cảm ứng lực và các thao tác Multi‑Touch\nCảm biến ánh sáng môi trường", "Bảo mật": "Touch ID", "Webcam": "Camera 12MP Center Stage có hỗ trợ chế độ Desk View\nQuay video HD 1080p\nBộ xử lý tín hiệu hình ảnh tiên tiến với video điện toán", "Hệ điều hành": "macOS"}, "Pin & công nghệ sạc": {"Pin": "Thời gian xem video trực tuyến lên đến 24 giờ\nThời gian duyệt web trên mạng không dây lên đến 16 giờ\nPin Li-Po 72.4 watt-giờ"}, "Cổng kết nối": {"Wi-Fi": "Wi‑Fi 6E (802.11ax)", "Bluetooth": "Bluetooth 5.3", "Cổng giao tiếp": "Khe thẻ nhớ SDXC\nCổng HDMI\nJack cắm tai nghe 3.5 mm\nCổng MagSafe 3\nBa cổng Thunderbolt 4 (USB‑C) hỗ trợ: Sạc / DisplayPort / Thunderbolt 4 (lên đến 40Gb/s) / USB 4 (lên đến 40Gb/s)"}}', 'CAT3');
