 Gian với khả năng theo dõi chuyển động đầu chủ động khi sử dụng AirPods (thế hệ thứ 3 trở lên)"}, "Cổng kết nối": {"Khe đọc thẻ nhớ": "Có", "Wi-Fi": "Wi‑Fi 6E (802.11ax)", "Bluetooth": "Bluetooth 5.3", "Cổng giao tiếp": "Khe thẻ nhớ SDXC\nCổng HDMI\nJack cắm tai nghe 3.5 mm\nCổng MagSafe 3\nBa cổng Thunderbolt 5 (USB‑C) hỗ trợ: Sạc, DisplayPort, Thunderbolt 5 (lên đến 120Gb/s), Thunderbolt 4 (lên đến 40Gb/s), USB 4 (lên đến 40Gb/s)"}, "Tiện ích khác": {"Tính năng đặc biệt": "Bảo mật vân tay"}, "Tính năng khác": {"Loại đèn bàn phím": "Bàn phím Magic Keyboard có đèn nền", "Bảo mật": "Touch ID", "Webcam": "Camera 12MP Center Stage có hỗ trợ chế độ Desk View\nQuay video HD 1080p\nBộ xử lý tín hiệu hình ảnh tiên tiến với video điện toán", "Hệ điều hành": "macOS"}, "Pin & công nghệ sạc": {"Pin": "Pin Li-Po 72.4 watt-giờ\nThời gian xem video trực tuyến lên đến 22 giờ\nThời gian duyệt web trên mạng không dây lên đến 14 giờ"}, "Kích thước & Trọng lượng": {"Kích thước": "Dài: 22.12 cm x Cao: 1.55 cm x Rộng: 31.26 cm", "Trọng lượng": "1.60 kg"}}', 'CAT3');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD528', N'Mainboard ASRock A520M/AC D4 AM4 Wifi', N'ASRock', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/r/group_467_9.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/r/group_301_5__4.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/r/group_301_7__4.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/r/group_301_6__3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/r/group_301_8__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/r/group_301_9__1.png"]', N'{"Thông số khác": {"Chipset": "AMD", "Socket": "AM4", "Kích thước": "micro-ATX", "Khe RAM tối đa": "2", "Kiểu RAM hỗ trợ": "DDR4", "Dung lượng RAM tối đa": "64GB", "Bus Ram hỗ trợ": "DDR4 4600+(OC) / 4533(OC) / 4466(OC) / 4400(OC) / 4333(OC) / 4333(OC) / 4266(OC) / 4200(OC) / 4133(OC) / 4000(OC) / 3866(OC) / 3800(OC) / 3733(OC) / 3600(OC) / 3466(OC) / 3200 / 2933 / 2667 / 2400 / 2133 ECC & không phải ECC, bộ nhớ không đệm", "Lưu trữ": "CPU:\n1 x Ultra M.2 Socket (M2_1, Key M), hỗ trợ chế độ SATA3 6.0 Gb/giây & PCIe Gen3x4 (32 Gb/giây) loại 2242/2260/2280\nChipset:\n4 x SATA3 6.0 Gb/giây Connectors", "Cổng xuất hình": "Tùy chọn đầu ra đồ họa: HDMI", "Khe PCI": "1 x Khe cắm PCI Express 3.0 x16 (PCIE2: chế độ x16)\n1 x Khe cắm PCI Express 3.0 x1\n1 x Ổ cắm M.2 dọc (Phím E) với mô-đun WiFi-802.11ac PCIe WiFi đi kèm (ở I/O phía sau)", "LAN": "PCIE x1 Gigabit LAN 10/100/1000 Mb/giây\nRealtek RTL8111H\nHỗ trợ Wake-On-LAN\nHỗ trợ Lightning/ESD Protection\nHỗ trợ Energy Efficient Ethernet 802.3az\nHỗ trợ PXE", "Âm thanh": "Âm thanh HD 7.1 CH (Bộ giải mã âm thanh Realtek ALC887/897)\nHỗ trợ bảo vệ chống sét lan truyền", "Cổng I/O ở trong": "1 x SPI TPM Header\n1 x COM Port Header\n1 x Chassis Intrusion and Speaker Header\n1 x CPU Fan Connector (4 chân)*\n2 x Chassis Fan Connectors (4 chân) (Smart Fan Speed ​​Control)**\n1 x 24 pin ATX Power Connector\n1 x 4 pin 12V Power Connector\n1 x Front Panel Audio Connectors\n2 x USB 2.0 Header (Hỗ trợ 4 cổng USB 2.0) (Hỗ trợ ESD Protection)\n1 x USB 3.2 Gen1 Header (Hỗ trợ 2 cổng USB 3.2 Gen1) (Hỗ trợ ESD Protection)", "Cổng I/O phía sau": "2 x Cổng Ăng-ten\n1 x Cổng Chuột/Bàn phím PS/2\n1 x Cổng HDMI\n2 x Cổng USB 2.0 (Hỗ trợ Bảo vệ ESD)\n4 x Cổng USB 3.2 Gen1 (Hỗ trợ Bảo vệ ESD)\n1 x Cổng LAN RJ-45 có đèn LED (Đèn LED ACT/LINK và Đèn LED SPEED)\nGiắc cắm âm thanh HD: Đầu vào đường truyền / Loa trước / Micrô", "Hệ điều hành": "Microsoft Windows 10 64-bit / 11 64-bit", "Kết nối không dây": "Intel 802.11ac WiFi Modulebr>Hỗ trợ Bluetooth 4.2 / 3.0 + High speed class II\nHỗ trợ IEEE 802.11a/b/g/n/ac\nHỗ trợ Dual-Band (2.4/5 GHz)"}, "Thông tin hãng": {"Hãng sản xuất": "ASRock"}}', 'CAT7');
