INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD557', N'Máy ảnh kỹ thuật số Sony ZV-1 II Vlog On The Go_Lite', N'Sony', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_nh_k_thu_t_s_sony_zv-1_ii_vlog_on_the_go_lite_-_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_nh_k_thu_t_s_sony_zv-1_ii_vlog_on_the_go_lite_-_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_nh_k_thu_t_s_sony_zv-1_ii_vlog_on_the_go_lite_-_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_7__2_172_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_1__7_35.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_2__7_23.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_6__2_184.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_5__8_19.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_4__7_19.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_6__2_217.png"]', N'{"Thông tin hãng": {"Hãng sản xuất": "Sony"}, "Thông tin chung": {"Loại máy ảnh": "Mirrorless (không gương lật)", "Độ nhạy ISO": "Video\nChế độ thủ công, tự động 125 đến 12.800\nẢnh\nChế độ thủ công 125 đến 12.800 (Mở rộng: 80 đến 12.800)\nChế độ tự động 125 đến 12.800", "Tốc độ chụp liên tục": "Màn trập điện tử: Lên tới 24 khung hình/giây cho tối đa 189 Khung hình (JPEG) / 80 khung hình (RAW)", "Chế độ cân bằng trắng": "2500 đến 9900K\nCài đặt trước: Tự động, Có mây, Ánh sáng ban ngày, Đèn nháy, Huỳnh quang (Trắng mát), Huỳnh quang (Trắng ban ngày), Huỳnh quang (Ánh sáng ban ngày), Sợi đốt, Bóng râm, Dưới nước", "Màn trập": "Màn trập điện tử\nẢnh tĩnh: 1/32000 đến 1/4 giây\nPhim: 1/12800 đến 1 giây"}, "Cảm biến": {"Loại cảm biến": "CMOS Exmor RS BSI 1\"", "Độ phân giải": "20.1MP"}, "Ống kính": {"Loại ống kính": "Ống kính ZEISS 