INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD558', N'Máy chụp ảnh phim Fujifilm Quicksnap Flash Superia 400 27exp', N'Fujifilm', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/s/s/ssss_1__1_74.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/s/s/ssss_2__1_71.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/s/s/ssss_2_127.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/s/s/ssss_3__1_66.png"]', N'{"Thông tin hãng": {"Hãng sản xuất": "Fujifilm"}, "Thông tin chung": {"Loại máy ảnh": "Máy ảnh phim", "Độ nhạy ISO": "ISO 400 (film Superia X-TRA400)", "Màn trập": "1/100 giây", "Điều kiện hoạt động": "Ngoài trời (trời nắng hoặc hơi nhiều mây)"}, "Ống kính": {"Loại ống kính": "Ống kính nhựa, 32mm f/10, ống kính lấy nét cố định", "Khẩu độ": "f/10", "Tiêu cự": "32 mm", "Khoảng cách lấy nét": "1m – vô cực"}, "Ảnh": {"Tỷ lệ ảnh": "3:2 (film 35mm)", "Định dạng ảnh": "Film 135 (27 kiểu chụp)"}, "Màn hình": {"Loại kính ngắm": "Kính ngắm kiểu Galilean đảo ngược bằng nhựa"}, "Flash": {"Đèn Flash": "Có (tích hợp)", "Chế độ Flash": "Flash tự động (bật khi cần)"}, "Kích thước & Trọng lượng": {"Kích thước": "115 x 54 x 34 mm", "Trọng lượng": "90 g"}, "Tiện ích": {"Tiện ích": "Máy ảnh film dùng một lần (disposable)\nFlash tích hợp (tầm hiệu quả 1 – 3m)\nKính ngắm quang học Galilean\nDễ sử dụng, không cần cài đặt"}}', 'CAT8');
