INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD843', N'Robot hút bụi lau sàn Dreame D30 Ultra', N'Dreame', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-11.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-12.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-13.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-14.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-8.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi", "Lực hút": "25.000Pa", "Dung tích ngăn chứa bụi": "3,2L", "Ứng dụng kết nối": "Dreamhome", "Pin": "5.200mAh"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển từ xa bằng app và giọng nói\nTTrạm dock tự động đổ rác\nKhay giặt giẻ tự làm sạch AceClean™\nThiết lập vùng cấm và tường ảo trong app\nLên lịch dọn dẹp tự động"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Trọng lượng robot hút bụi: 3,91kg\nTrọng lượng trạm sạc: 8,62kg", "Kích thước": "Kích thước robot: 35 × 35 × 9.7 cm\nKích thước trạm sạc: 45.7 × 34 × 59 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Lực hút Vormax™ 25.000Pa với 5 mức lực hút\nHút và lau 2 trong 1 với hệ thống lau xoay DuoScrub™\nMopExtend™ RoboSwing mở rộng giẻ lau\nTự nâng giẻ lau ~10.5 mm khi gặp thảm"}}', 'CAT5');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD844', N'Robot hút bụi lau sàn chuyên dụng Dreame F20', N'Dreame', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-13.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-8.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-11.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-12.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-7.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "270 ml", "Lực hút": "20.000 Pa", "Dung tích ngăn chứa bụi": "220 ml", "Ứng dụng kết nối": "Dreamhome", "Pin": "3200 mAh"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Chống rối tóc - lông thú", "Tiện ích": "Điều khiển từ xa bằng app và giọng nói\nTrang bị hệ thống điều hướng Smart Pathfinder™, giúp nhận diện vật cản và di chuyển thông minh\nTự quay về trạm sạc khi pin yếu\nTối ưu làm sạch khe hở và mép sàn"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Trọng lượng robot hút bụi: 2,55kg\nTrọng lượng trạm sạc: 0,29kg", "Kích thước": "Kích thước robot: 32.5 × 32.5 × 9.47 cm\nKích thước trạm sạc: 14.6 × 6 × 9.86 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Lực hút Vormax™ 20.000Pa làm sạch sâu\nXử lý 100%* các hạt bụi lớn\nHút và lau 2 trong 1, hỗ trợ 32 mức điều chỉnh lượng nước\nThiết lập vùng cấm lau"}}', 'CAT5');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD845', N'Robot hút bụi lau nhà tự động làm sạch Dreame Bot L10 Prime (Bản quốc tế)', N'Dreame', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime_1_2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime_2__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime_3__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime_4__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-5_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-4_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-6_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-7_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-8_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-9_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-2_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-3_3.png"]', N'{"Thông số kỹ thuật": {"Dòng điện vào": "100-240 V"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Tốc độ xoay miếng lau: 180 vòng/phút\nTrợ lý ảo Amazon Alexa, Google Assistant hay Apple Siri\nTự động nâng giẻ lau thông minh 7mm\nKhả năng vượt gờ 20mm\nLưu trữ tối đa 3 bản đồ\nĐiều hướng LiDAR và LDS\nHệ thống định vị SLAM nâng cấp"}, "Thông tin chung": {"Thời gian hoạt động": "210 phút (Chế độ im lặng - Quite Mode)\n150 phút (Chế độ tiêu chuẩn - Standard)", "Dung tích ngăn chứa nước": "Nước sạch: 2.7 L\nNước bẩn: 2.5 L", "Lực hút": "4000 Pa", "Dung tích ngăn chứa bụi": "Robot hút bụi: 450 mL", "Ứng dụng kết nối": "DreameHome", "Pin": "5200 mAh", "Khoang chứa bụi": "Khoang chứa, Túi chứa"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Robot: 3.65 Kg\nTrạm sạc: 5.72 Kg", "Kích thước": "Robot: 350 x 350 x 103.8 mm\nTrạm sạc: 340 x 430 x 440 mm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Thông số khác": {"Kết nối": "Wi-Fi IEEE 802.11b/g/n 2.4 GHz"}}', 'CAT5');
