ng", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/r/frame_26_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/r/frame_27_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/r/frame_28_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/r/frame_30_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/f/r/frame_31_.png"]', N'{"Màn hình": {"Công nghệ màn hình": "Màn hình AMOLED\nĐộ sáng tối đa lên đến 1500 nit", "Kích thước màn hình": "1.62 inch", "Độ phân giải": "286 × 482 pixel, PPI 347"}, "Thiết kế": {"Chất liệu mặt kính": "Kính cường lực", "Chất liệu viền": "Hợp kim", "Đường kính mặt": "42.6 mm", "Thiết kế": "Mặt chữ nhật", "Trọng lượng": "17g"}, "Dây đeo": {"Chất liệu dây": "Cao Su", "Bề rộng dây": "2.2 cm", "Kích thước cổ tay phù hợp": "Đen, xanh lá, trắng: 130 - 210 mm\nTím, Beige: 120 - 190 mm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Không", "Kháng nước": "5 ATM", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Theo dõi chu kỳ, Tình trạng HRV (Heart Rate Variability)", "Tính năng thể thao": "100+ chế độ luyện tập\nYoga\nCầu lông\nChạy bộ\nBơi lội\nBóng đá", "Thông báo": "Cuộc gọi, tin nhắn, ứng dụng", "Tiện ích khác": "Chế độ luyện tập, Hiển thị thông báo điện thoại, Nhận thông báo cuộc gọi, Bấm giờ, Báo thức, Tìm điện thoại, Điều khiển chụp ảnh, Dự báo thời tiết, Máy tính, Lịch, Tìm đồng hồ, Quản lý tiến độ tập luyện, Thiết lập mục tiêu lộ trình (Route Target)", "Tính năng đặc biệt": "Phân Tích Rối Loạn Nhịp Tim Qua Sóng Mạch\nChế độ dành riêng cho người dùng xe lăn"}, "Kích thước & Trọng lượng": {"Kích thước": "42.6×28.2×8.99mm"}, "Cấu hình": {"Kết nối": "2.4 GHz, Bluetooth 6.0 và BLE", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "HarmonyOS", "Tương thích": "Android 9.0 trở lên\niOS 13.0 trở lên", "Ứng dụng kết nối": "Huawei Health", "Cảm biến": "Cảm biến IMU 9 trục (Cảm biến gia tốc kế, cảm biến con quay hồi chuyển, cảm biến từ kế)\nCảm biến nhịp tim quang học\nCảm biến ánh sáng"}, "Pin": {"Thời lượng pin": "Thời lượng sử dụng tối đa 14 ngày.\nThời lượng sử dụng thường xuyên 8 ngày.\nThời lượng sử dụng 3 ngày khi bật AOD.", "Thời gian sạc": "Khoảng 45 phút", "Dung lượng pin": "300 mAh", "Cổng sạc": "Đế sạc từ tính"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Anh, Tiếng Việt, Tiếng Trung", "Thời gian ra mắt": "03/2026", "Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Huawei"}}', 'CAT4');
