INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD969', N'Vòng đeo tay thông minh Xiaomi Mi Band 10 Pro', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dhnn_3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dhnn_3__3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dhnn_2__3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dhnn_1__3.png"]', N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.74 inch", "Độ phân giải": "480 × 336 pixels\nĐộ sáng tối đa 2000 nits"}, "Thiết kế": {"Chất liệu viền": "Nhôm", "Thiết kế": "Mặt vuông", "Trọng lượng": "21.5 gram (không bao gồm dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Cao Su", "Kích thước cổ tay phù hợp": "Từ 13.5 – 20.5 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Kháng nước": "5 ATM", "Tiện ích sức khoẻ": "Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đo mức độ stress, Theo dõi chu kỳ", "Tính năng thể thao": "Hơn 150 chế độ thể thao\nChế độ sân chơi & chế độ đạp xe mới\nHỗ trợ đo nhịp tim dưới nước", "Thông báo": "Tin nhắn, cuộc gọi", "Tiện ích khác": "Màn hình luôn hiển thị"}, "Cấu hình": {"Kết nối": "Bluetooth 5.4", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "Khác", "Tương thích": "Android, iOS", "Ứng dụng kết nối": "Mi Fitness", "Cảm biến": "Cảm biến gia tốc, Cảm biến con quay hồi chuyển, Cảm biến nhịp tim quang học và SpO₂, Cảm biến ánh sáng môi trường, Cảm biến từ trường"}, "Pin": {"Thời lượng pin": "Thời lượng pin mở rộng lên đến 21 ngày\n7 ngày sử dụng trong chế độ AOD (Always-On Display)", "Dung lượng pin": "350 mAh"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Việt, Tiếng Anh, Tiếng Trung", "Thời gian ra mắt": "03/2026", "Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}}', 'CAT4');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD970', N'Xreal HUB – Hỗ trợ sạc và xuất hình ảnh', N'Hãng khác', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/x/r/xreal-hub-ho-tro-sac-va-xuat-hinh-anh_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/x/r/xreal-hub-ho-tro-sac-va-xuat-hinh-anh_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/x/r/xreal-hub-ho-tro-sac-va-xuat-hinh-anh_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/x/r/xreal-hub-ho-tro-sac-va-xuat-hinh-anh_3_.png"]', N'{"Tổng quan": {"Công suất sạc": "45W"}, "Công nghệ và tiện ích": {"Tiện ích": "Sạc nhanh\nTương thích với Steam Deck, Nintendo Switch, iPhone 15, Rog Ally v.v…"}, "Thông tin hãng": {"Hãng sản xuất": "Hãng khác"}}', 'CAT1');
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1', 'PROD1', N'Trắng', 2290000.00, 34, N'{"Công nghệ âm thanh": {"Công nghệ âm thanh": "Trình điều khiển Apple với độ lệch tương phản cao có thể tùy chỉnh\nBộ khuếch đại với độ lệch tương phản cao có thể tùy chỉnh\nTách Lời Nói\nChế độ Âm Thanh Không Gian Cá Nhân Hóa với tính năng theo dõi chuyển động đầu chủ động\nEQ Thích Ứng H", "Micro": "Có", "Tính năng": "Chống ồn, Điều khiển giọng nói, Xuyên âm, Có mic đàm thoại, Sạc không dây"}, "Khả năng kết nối": {"Bluetooth": "5.3"}, "Thời lượng pin - sạc": {"Dung lượng pin": "Thời gian nghe lên đến 5 giờ với một lần sạc\nThời gian đàm thoại lên đến 4,5 giờ với một lần sạc", "Cổng sạc": "USB-C", "Thời gian sạc": "Hãng không công bố"}, "Điều khiển": {"Phương thức điều khiển": "Cảm ứng chạm"}, "Kích thước & Trọng lượng": {"Kích thước": "Tai nghe: 30.2 x 18.3 x 18.1 mm\nHộp sạc: 46.2 x 50.1 x 21.2 mm", "Trọng lượng": "Tai nghe: 4.3g\nHộp sạc: 32.3g"}, "Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}, "Chống nước": {"Chống nước": "IP54"}}', N'', N'https://cellphones.com.vn/media/catalog/product/t/a/tai_nghe_bluetooth_apple_airpods_4.png', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR2', 'PROD2', N'Cam', 14990000.00, 79, N'{"Kích thước & Trọng lượng": {"Kích thước": "168.6 x 187.3 x 83.4 mm", "Trọng lượng": "AirPods Max 2, bao gồm đệm tai: 386,2 gram\nSmart Case: 134,5 gram"}, "Công nghệ âm thanh": {"Công nghệ âm thanh": "Trình điều khiển động do Apple thiết kế\nBộ khuếch đại với độ lệch tương phản cao có thể tùy chỉnh\nChủ Động Khử Tiếng Ồn Âm Thanh Thích Ứng\nChế độ Xuyên Âm\nNhận Biết Cuộc Hội Thoại\nTách Lời Nói\nÂm Lượng Được Cá Nhân Hóa\nGiảm Âm", "Micro": "Tổng cộng chín micrô:\nTám micrô dành cho tính năng Chủ Động Khử Tiếng Ồn\nBa micrô dành cho tính năng nhận diện giọng nói (hai micrô dùng chung với tính năng Chủ Động Khử Tiếng Ồn và một micrô bổ sung)", "Tính năng": "Xuyên âm, Có mic đàm thoại, Chống ồn chủ động ANC", "Cảm biến": "Cảm biến quang học (mỗi bên củ tai)\nCảm biến vị trí (mỗi bên củ tai)\nCảm biến phát hiện hộp (mỗi bên củ tai)\nGia tốc kế (mỗi bên củ tai)\nCon quay hồi chuyển (củ tai bên trái)"}, "Khả năng kết nối": {"Bluetooth": "5.3"}, "Thời lượng pin - sạc": {"Thời lượng sử dụng Pin": "Lên đến 20 giờ với một lần sạc khi bật tính năng Chủ Động Khử Tiếng Ồn", "Cổng sạc": "Cáp Sạc USB-C"}, "Điều khiển": {"Thao tác điều khiển": "Digital Crown\nXoay để điều khiển âm lượng\nNhấn một lần để phát hoặc tạm dừng phương tiện\nNhấn một lần để trả lời cuộc gọi, bật hoặc tắt tiếng\nNhấn một lần để mở điều khiển camera\nNhấn hai lần để kết thúc cuộc gọi\nNhấn hai lần để tua tớ"}, "Tính năng - Tiện ích khác": {"Tính năng khác": "Các tính năng Trợ Năng giúp người khuyết tật tận dụng tối đa AirPods Max mới của mình.\nCác tính năng bao gồm:\nÂm thanh Nghe Trực Tiếp\nMức âm thanh tai nghe\nThích Nghi Tai Nghe"}, "Vi xử lý & đồ họa": {"Chipset": "Chip tai nghe Apple H2 (mỗi bên củ tai)"}, "Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}}', N'AirPods Max 2 2026', N'https://cellphones.com.vn/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2_2_.png', 'New', 0);
