INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR9', 'PROD4', N'Xám không gian', 20890000.00, 50, N'{"Màn hình": {"Kích thước màn hình": "11 inches", "Công nghệ màn hình": "Liquid Retina", "Độ phân giải màn hình": "2360 x 1640 pixel", "Tính năng màn hình": "Màn hình Multi-Touch với công nghệ LED nền và IPS\nĐộ sáng 500 nit\n264 ppi\nDải màu rộng (P3)\nTrue Tone\nLớp phủ chống phản chiếu\nCông nghệ ép kín"}, "Camera sau": {"Camera sau": "12MP, f/1.8, Độ thu phóng kỹ thuật số lên đến 5x\nChụp ảnh toàn cảnh Panorama (lên đến 63MP)", "Quay video": "4K ở tốc độ 24/25/30/60fps\nHD 1080p ở tốc độ 25/30/60fps\nHD 720p ở tốc độ 30 fps", "Tính năng camera": "Tự động lấy nét theo pha Focus Pixels\nHDR thông minh thế hệ 4\nLive Photos\nĐịnh vị ảnh\nTự động chống rung hình ảnh\nChế độ Chụp liên tục\nFlash Retina với True Tone\nHiệu chỉnh ống kính"}, "Camera trước": {"Camera trước": "12MP Center Stage, ƒ/2.0", "Quay video trước": "Quay video HD 1080p @ 25 fps, 30 fps, hoặc 60 fps"}, "Vi xử lý & đồ họa": {"Chipset": "Chip Apple M4", "GPU": "GPU 9 lõi\nNeural Engine 16 lõi\nCông nghệ dò tia tốc độ cao bằng phần cứng"}, "RAM & lưu trữ": {"Dung lượng RAM": "8 GB", "Bộ nhớ trong": "128 GB"}, "Pin & công nghệ sạc": {"Pin": "Tích hợp pin sạc Li-Po 28,93 watt‑giờ", "Cổng sạc": "USB Type-C"}, "Giao tiếp & kết nối": {"Thẻ SIM": "1 eSIM", "Hỗ trợ mạng": "5G", "GPS": "GPS/GNSS"}, "Tính năng khác": {"Hệ điều hành": "iPadOS 26"}, "Bộ xử lý & Đồ họa": {"Loại CPU": "8 lõi với 3 lõi hiệu năng và 5 lõi tiết kiệm điện"}, "Kích thước & Trọng lượng": {"Kích thước": "247,6 x 178,5 x 6,1 mm", "Trọng lượng": "465 g"}, "Thông số khác": {"Tương thích": "Hỗ trợ Apple Pencil Pro\nHỗ trợ Apple Pencil (USB-C)\nHỗ trợ Magic Keyboard cho iPad Air", "Công nghệ - Tiện ích": "FaceTime video\nFaceTime âm thanh\nTrung Tâm Màn Hình iPad gọi đến thiết bị bất kỳ có hỗ trợ\nFaceTime qua Wi-Fi hoặc mạng di động", "Tiện ích khác": "Touch ID", "Công nghệ âm thanh": "Loa stereo ở cạnh trên và cạnh dưới\nHai micrô để gọi, quay video và ghi âm\nÂm Thanh Không Gian"}, "Tiện ích khác": {"Cảm biến vân tay": "Cảm biến vân tay cạnh bên", "Các loại cảm biến": "Cảm biến ánh sáng, Con quay hồi chuyển, Cảm biến áp kế"}, "Cổng kết nối": {"Wi-Fi": "Wi-Fi 7 (802.11be) với 2x2 MIMO5", "Bluetooth": "Bluetooth 6"}}', N'5G 128GB', N'https://cellphones.com.vn/media/catalog/product/x/_/x_m_1__1_4.png', 'New', 0);
