INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR73', 'PROD8', N'Bạc', 44990000.00, 20, N'{"Thông số màn hình": {"Nghiêng": "−5° đến +25°", "Điều chỉnh độ cao": "Tổng cộng 105 mm", "Treo tường": "100 x 100 mm"}, "Màn hình": {"Tần số quét": "60 Hz", "Kích thước màn hình": "27 inches", "Công nghệ màn hình": "Màn hình Retina\nĐộ sáng 600 nit\nHỗ trợ một tỷ màu\nDải màu rộng (P3)\nCông nghệ True Tone", "Độ phân giải màn hình": "5120 x 2880 pixels"}, "Âm thanh": {"Công nghệ âm thanh": "Hệ thống âm thanh sáu loa có độ trung thực cao với loa trầm khử lực\nÂm thanh stereo rộng\nHỗ trợ Âm Thanh Không Gian khi phát nhạc hoặc video với Dolby Atmos\nBa micrô chuẩn studio kết hợp\nHỗ trợ “Hey Siri”"}, "Tính năng khác": {"Webcam": "Camera 12MP Center Stage cùng chế độ Desk View"}, "Kích thước & Trọng lượng": {"Kích thước": "Studio Display với chân đế có thể điều chỉnh độ nghiêng: 47.9 x 62.3 x 20.7 cm (Cao x Rộng x Dày)\nStudio Display với ngàm kết nối VESA: 36.2 x 62.3 x 3.1 cm (Cao x Rộng x Dày)", "Trọng lượng": "Studio Display với chân đế có thể điều chỉnh độ nghiêng: 6.3 kg\nStudio Display với ngàm kết nối VESA: 5.4 kg"}, "Cổng kết nối": {"Cổng giao tiếp": "2x Thunderbolt 5 (120Gb/s), 1 cổng ngược dòng dành cho thiết bị chính (96W), 1 cổng xuôi dòng để kết nối phụ kiện tốc độ cao hoặc kết nối chuỗi các màn hình khác\n2x USB-C (10Gb/s) để kết nối các thiết bị ngoại vi, lưu trữ và kết nối mạng"}}', N'Chân Đế Cố Định', N'https://cellphones.com.vn/media/catalog/product/s/t/studio_display_pdp_image_position_1__vn-vi_1.jpg', 'New', 0);
