INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR147', 'PROD45', N'Cream Yellow Pro Switch', 1490000.00, 50, N'{"Tổng quan": {"Loại bàn phím": "Tenkeyless 75%", "Số phím": "82 phím", "Keycap": "PBT Double-Shot\nOEM profile, xuyên LED", "Phím đặc biệt": "Núm xoay chỉnh", "Tương thích": "Windows / MacOS / Linux"}, "Kết nối và đèn LED": {"Kết nối": "Không dây: Bluetooth 5.0 và USB 2.4GHz\nCó dây: Dây cáp USB Type-C có thể tháo rời", "Khoảng cách kết nối (Độ dài dây)": "10 mét", "Đèn LED": "LED nền RGB (6028 SMD LED) với nhiều chế độ\nLED 2 bên hông phím", "Ứng dụng kết nối": "Tích hợp AKKO Cloud Driver (Hỗ trợ Audio Visualizer ở chế độ kết nối 2.4Ghz) có thể keymap và chỉnh LED / Macro"}, "Pin và tiện ích": {"Pin": "3000 mAh", "Thời gian dùng": "Khoảng 10 ngày ở chế độ không dây và không bật LED", "Tiện ích": "Keyboard Rollover: N-Key\nĐộ bền Switch: 60 triệu lượt nhấn\nFoam tiêu âm và switch pad bằng silicon\nHotSwap (5-pin)\nHỗ trợ Audio Visualizer ở chế độ kết nối 2.4GHz\nNúm (Knob) kim loại phun sơn (có thể bị xước, nên cẩn thận khi sử dụng)\nCấu trúc Gasket mount + Plate PC giúp âm gõ đều nhau ở các row\nHỗ trợ NKRO / Multimedia / Macro / Khóa phím Win\nTùy chỉnh thời gian nghỉ và độ nhạy phím\nCheck lượng pin còn lại trong phần mềm AKKO Cloud Driver", "Cổng sạc": "Cáp USB-C"}, "Thiết kế và khối lượng": {"Kích thước": "33.5 x 14.6 x 4.2 cm", "Khối lượng": "1.1 kg"}, "Thông tin hãng": {"Hãng sản xuất": "AKKO"}}', N'5075B Plus
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR148', 'PROD46', N'Star Vector Switch', 1399000.00, 57, N'{"Tổng quan": {"Loại bàn phím": "Tenkeyless", "Số phím": "81 phím", "Keycap": "PBT Double-Shot", "Phím đặc biệt": "Núm xoay đa chức năng (điều chỉnh âm thanh/ánh sáng)", "Tương thích": "WIN7/WIN8/WIN10/Android/IOS/MAC"}, "Kết nối và đèn LED": {"Kết nối": "3 mode có dây Type-C & không dây 2.4G & BT", "Khoảng cách kết nối (Độ dài dây)": "Không dây: 10 m", "Đèn LED": "LED RGB 16 hiệu ứng"}, "Pin và tiện ích": {"Pin": "4000 mAh", "Thời gian dùng": "Thời gian sử dụng sau khi sạc đầy pin: Khoảng 22H (hiệu ứng ánh sáng mặc định) Khoảng 266H (tắt tất cả đèn)", "Tiện ích": "Độ bền: 60 triệu lần bấm\nHiệu ứng âm thanh khi gõ phím: Linear\nHot-Swap 5 pin\nGasket mount\nMạch xuôi\nCấu trúc âm thanh 5 lớp\nTấm định vị PC\nPCB có khe rãnh riêng cho từng switch\nĐiện áp/dòng sạc: DC 5V/ 800mA\nĐiện áp định mức: DC 3.7V", "Cổng sạc": "Type-C"}, "Thiết kế và khối lượng": {"Kích thước": "33.63 x 14.7 x 4.43 cm", "Khối lượng": "977.3 g"}, "Thông tin hãng": {"Hãng sản xuất": "Aula"}}', N'AU75
