INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR151', 'PROD48', N'Dream Sakura Switch', 1399000.00, 79, N'{"Tổng quan": {"Loại bàn phím": "Tenkeyless 75%", "Số phím": "80 phím", "Keycap": "Nhựa PBT 2 màu", "Phím đặc biệt": "Phím tăng giảm âm lượng/độ sáng của đèn", "Tương thích": "WINXP/WIN7/WIN8/WIN10\nAndroid/IOS/MAC", "Nút nhấn": "Hiệu ứng âm thanh khi gõ phím: Linear"}, "Kết nối và đèn LED": {"Kết nối": "3 mode có dây Type-C & không dây 2.4G & Bluetooth", "Khoảng cách kết nối (Độ dài dây)": "Độ dài dây:1.6m", "Đèn LED": "LED RGB 16.8 triệu màu, 16 loại hiệu ứng"}, "Pin và tiện ích": {"Pin": "Pin lithium 4000mAh có thể sạc lại\nThời gian sạc khoảng 4 tiếng", "Thời gian dùng": "Khoảng 30.5 giờ (hiệu ứng ánh sáng mặc định) và khoảng 80 giờ (tắt led)", "Tiện ích": "Hot-Swap 5 pin\nGasket mount\nNúm xoay đa chức năng\nMàn hình hiển thị thông tin và hình ảnh\nMạch xuôi\nThiết kế cấu trúc gasket với sáu lớp vật liệu cách âm\nĐiện áp/dòng sạc: DC 5V-1050mA\nĐiện áp định mức: DC 3.7V (đầy đủ 4.2V)\n5 lớp giảm tiếng ồn\nCấu trúc đệm Leaf Spring\nTấm định vị PC có rãnh\nMiếng đệm cách âm PET\nBông giảm thanh PORON\nPhím đơn PCB có rãnh 1.2mm", "Chất liệu": "Khuôn silicone ở dưới cùng", "Cổng sạc": "Dây sạc Type-C"}, "Thiết kế và khối lượng": {"Kích thước": "32.27 × 14.32 × 4.31 cm", "Khối lượng": "Khoảng 975g (không có cáp/bộ thu)/ 1023g (với cáp/bộ thu)"}, "Thông tin hãng": {"Hãng sản xuất": "Aula"}}', N'', N'https://cellphones.com.vn/media/catalog/product/m/_/m_y_c_o_r_u_22_46__2.png', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR152', 'PROD49', N'Dream Sakura Switch', 1799000.00, 33, N'{"Tổng quan": {"Loại bàn phím": "Full-size", "Số phím": "99 phím", "Keycap": "Nhựa PBT Double-Shot", "Tương thích": "WIN XP7/8/10/Android/IOS/MAC"}, "Kết nối và đèn LED": {"Kết nối": "3 mode có dây Type-C & không dây 2.4G & BT", "Khoảng cách kết nối (Độ dài dây)": "1.6 m\nKhoảng cách kết nối 10 m", "Đèn LED": "LED RGB với 16 loại hiệu ứng ánh sáng"}, "Pin và tiện ích": {"Pin": "Pin Li-ion có thể sạc lại 8000mAh (2*4000mAh)", "Thời gian dùng": "Khoảng 53 giờ (hiệu ứng ánh sáng mặc định)/ 400 giờ (tất cả đèn tắt)", "Tiện ích": "Độ bền phím: 60 triệu lần bấm\nHiệu ứng âm thanh khi gõ phím: Linear\nHot-Swap 5 pin\nGasket mount\nMạch ngược\nĐiện áp định mức:DC 3.7V (Đầy đủ 4.2V)\nĐiện áp/Dòng điện sạc: DC 5V/≦830mA\nDòng điện định mức: 150mA @3.7V (hiệu ứng ánh sáng mặc định)/20 mA (tắt tất cả đèn)", "Chất liệu": "Nhựa ABS", "Cổng sạc": "Type C"}, "Thiết kế và khối lượng": {"Kích thước": "39 x 14.7 x 4.3 cm", "Khối lượng": "Khoảng 1132g (không có cáp/bộ thu)/ 1183g (với cáp/bộ thu)"}, "Thông tin hãng": {"Hãng sản xuất": "Aula"}}', N'', N'https://cellphones.com.vn/media/catalog/product/m/_/m_y_c_o_r_u_22_56__3.png', 'New', 0);
