INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR213', 'PROD91', N'Đen', 14000000.00, 66, N'{"Kích thước & Trọng lượng": {"Kích thước": "46 × 124,5 × 38,2mm", "Trọng lượng": "200g"}, "Dòng camera": {"Dòng camera": "Camera hành động"}, "Thông số camera": {"Độ phân giải": "72 MP (11904 x 5952)\n18MP (5888 x 2944)", "Cảm biến ảnh": "1/1,28\"", "Chip xử lý": "2 chip hình ảnh chuyên nghiệp ,1 chip AI 5nm", "Góc ống kính": "Khẩu độ ống kính F2.0\nĐộ dài tiêu cự 6mm", "Chất lượng video": "360°:\nChế độ video: 8K: 7680 x 3840 @ 30/25/24fps\nChế độ InstaFrame: 5.7K+: 30/25/24\nỐng kính đơn:\nChế độ video: 4K: 3840 x 2160@60/50/30/25/24 fps\nVideo FreeFrame: 4K: 3840 x 3840@30/25/24fps\nChế độ Me:\n4K: 3840 x 2160@30/25/24fps", "Ghi âm": "Tự động giảm tiếng ồn gió (hai mức)\nTăng cường giọng nói\nÂm thanh nổi\nÂm thanh 360°", "Thông số màn hình": "Giá trị phơi sáng: ±4EV\nPhạm vi ISO: 100 – 6400\nTốc độ màn trập Ảnh: 1/8000 - 120 giây Video: 1/8000 - ở giới hạn khung hình mỗi giây\nCân bằng trắng: 2000K - 10000K"}, "Lưu trữ và kết nối": {"Bộ nhớ": "UHS-I Speed ​​Class V30 trở lên", "Kết nối không dây": "Bluetooth: BLE 5.2\nWi-Fi: 802.11a/n/ac", "Kết nối có dây": "USB-C 3.0", "Ứng dụng hỗ trợ": "Insta360"}, "Nguồn điện": {"Thông số pin": "2400mAh\nTuổi thọ pin 185 phút\nSạc nhanh, bộ sạc USB-C 30W, 80% trong 20 phút (9V 2A) 100% trong 35 phút (9V 2A)"}, "Tính năng": {"Chống rung": "Ổn định FlowState + khóa đường chân trời 360°", "Tính năng khác": "Tốc độ bit video tối đa 180Mbps\nKháng nước 15m"}, "Thông tin hãng": {"Hãng sản xuất": "Insta360"}, "Tiện ích": {"Tính năng khác": "Chế độ chụp ảnh: Ảnh, Tua nhanh thời gian, Tua nhanh sao, Chụp liên tục\nChế độ video: 360°: Video, PureVideo, InstaFrame, Timelapse, TimeShift, Bullet Time, Ghi vòng lặp\nChế độ đường ống kính đơn: Video, Video FreeFrame, Chế độ Me, Ghi vòng lặp"}, "Thông số khác": {"Tiện ích": "Kính chắn gió tích hợp âm thanh rõ hơn, Ống kính có thể thay thế, Chế độ PureVideo chụp ảnh thiếu sáng tốt hơn, Chế độ InstaFrame, Kiểm soát bằng cử chỉ, Điều khiển bằng giọng nói 2.0"}}', N'X5', N'https://cellphones.com.vn/media/catalog/product/c/a/camera-hanh-trinh-insta-360-x5_1_1.png', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR214', 'PROD92', N'Đen', 0.00, 76, N'{"Kích thước & Trọng lượng": {"Kích thước": "71,9 x 52,2 x 38mm", "Trọng lượng": "177,2g"}, "Dòng camera": {"Dòng camera": "Camera hành động"}, "Thông số camera": {"Độ phân giải": "50MP (8192x6144)\n37MP (8192x4608)\n12.5MP (4096x3072)\n9MP (4096x2304)", "Cảm biến ảnh": "1/1,3\"", "Chip xử lý": "2 chip AI", "Góc ống kính": "Khẩu độ: F2.6\nGóc nhìn: 157° (Leica Ultra Wide)", "Chất lượng video": "8K (16:9): 7680x4320\n8K (2.35:1): 7680x3272\n4K (4:3): 3840×2880\n4K (16:9): 3840x2160\n4K (2.35:1): 3840x1632\n2.7K (4:3): 2688x2016\n2.7K (16:9): 2688x1520\n1440p (4:3): 1920x1440\n1080p (16:9): 1920x1080\nChế độ Purevideo 4k60fps", "Ghi âm": "3 Micro", "Thông số màn hình": "Giá trị phơi sáng: ±4EV\nPhạm vi ISO: 100-6400\nTốc độ màn trập Ảnh: 1/8000 - 120 giây, Video: 1/8000 - đến giới hạn khung hình mỗi giây\nCân bằng trắng: 2000–10000K (tự động)\nBitrate tối đa: lên đến 180Mbps"}, "Lưu trữ và kết nối": {"Bộ nhớ": "Hỗ trợ thẻ nhớ microSD lên đến 1TB", "Kết nối không dây": "Bluetooth: BLE 5.2\nWi-Fi: 2,4 GHz, 5 GHz 802.11 a/b/g/n/ac", "Ứng dụng hỗ trợ": "Insta360 App"}, "Nguồn điện": {"Thông số pin": "1800mAh\nThời gian sạc: 47 phút (với sạc nhanh 30W) 75 phút với sạc 5V/3A Thời gian sử dụng: 180 phút"}, "Tính năng": {"Chống rung": "FlowState và khóa đường chân trời 360°", "Quay phim siêu chậm": "4K (16:9): 3840x2160@120/100fps\n2.7K (16:9):2688x1520@120/100fps\n1080p (16:9): 1920x1080@240/200/120/100fps", "Tính năng khác": "Chống nước 12m (60m với hộp lặn)\nMàn hình cảm ứng lật 2,5\"\nKiểm soát bằng cử chỉ\nĐiều khiển bằng giọng nói 2.0"}, "Thông tin hãng": {"Hãng sản xuất": "Insta360"}, "Thông số kỹ thuật": {"Cổng sạc ra": "USB-C 3.0"}, "Tiện ích": {"Tính năng khác": "Định dạng video: MP4\nĐịnh dạng ảnh: JPG DNG RAW\nMã hoá video: H.264, H.265\nChế độ âm thanh: Giảm gió, Tăng cường giọng nói, Âm thanh nổi\nĐịnh dạng âm thanh: 48 kHz, 16-bit, AAC"}, "Thông số khác": {"Tiện ích": "Chế độ video: Video (có Active HDR tích hợp), FreeFrame Video, PureVideo, Chuyển động chậm, Starlapse, Timelapse, TimeShift, Ghi vòng lặp, Dashcam, Ghi trước\nChế độ ảnh: Ảnh, Ảnh HDR, Ảnh Interval, Ảnh Burst, Chụp nhanh hình sao"}}', N'', N'https://cellphones.com.vn/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-1_1.jpg', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR215', 'PROD93', N'Đen', 1290000.00, 65, N'{"Thông số kỹ thuật": {"Dòng điện vào": "5V/1.5A"}, "Dòng camera": {"Dòng camera": "Dùng cho Oto", "Vị trí lắp đặt trên xe": "Gắn kính chắn gió"}, "Thông số camera": {"Cảm biến ảnh": "G-Sensor", "Góc ống kính": "Góc rộng 150°", "Chất lượng video": "Full HD (1920 x 1080p)", "Ghi âm": "Có", "Thông số màn hình": "LCD 0.96 inch"}, "Lưu trữ và kết nối": {"Bộ nhớ": "MicroSD (Hỗ trợ thẻ tối đa 128GB)", "Kết nối không dây": "Wi-Fi", "Ứng dụng hỗ trợ": "VIETMAP REC"}, "Nguồn điện": {"Nguồn điện trực tiếp": "5V - 1.5A", "Thông số pin": "Siêu tụ"}, "Tính năng": {"Kết nối phụ kiện rời": "Giá đỡ 3M", "Tính năng khác": "Kết nối WIFI chia sẻ video\nGhi hình vòng lặp khi thẻ nhớ đầy\nDễ dàng lắp đặt, không gây cản trở tầm nhìn\nTự động khóa và bảo vệ video khi xảy ra va chạm, rung lắc"}, "Thông tin hãng": {"Hãng sản xuất": "Vietmap"}}', N'', N'https://cellphones.com.vn/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_2__1.png', 'New', 0);
