INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR371', 'PROD190', N'Xám', 990000.00, 20, N'{"Tổng quan": {"Công suất sạc": "120W", "Sử dụng tối đa": "4 thiết bị", "Đầu vào": "AC", "Đầu ra": "3 x USB-C\n1 x USB-A", "Nguồn vào": "200 - 240V ~ 50/60Hz 1.7A", "Nguồn ra": "USB-C (1)+(2): 5V–3A, 9V–3A, 12V–3A, 15V–3A, 20V–5A, 11V–6.1A (100W Max)\nUSB-C (3): 5V–3A, 9V–3A, 12V–2.5A, 15V–2A, 11V–4A (44W Max)\nUSB-A: 5V–3A, 9V–3A, 12V–1.5A, 11V–3A (33W Max)"}, "Công nghệ và tiện ích": {"Tiện ích": "Sạc nhanh\nSạc cùng lúc nhiều thiết bị\nMàn hình LED 1.57 inch hiển thị thông số sạc\nHỗ trợ ứng dụng Mi Home theo dõi công suất\nTích hợp cảm biến nhiệt NTC kiểm tra 36.000 lần/giờ", "Công nghệ/Đạt chứng nhận": "PD3.1, PPS, UFCS, QC, Huawei SCP/FCP, Xiaomi Turbo 120W"}, "Thiết kế và trọng lượng": {"Kích thước": "67 x 76 x 33 mm"}, "Thông tin hãng": {"Hãng sản xuất": "Cuktech"}}', N'Kèm cáp', N'https://cellphones.com.vn/media/catalog/product/c/u/cu-sac-cuktech-3c1a-no-10-man-hi.jpg', 'New', 0);
