INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR381', 'PROD198', N'Xám', 490000.00, 55, N'{"Tổng quan": {"Công suất sạc": "65W", "Sử dụng tối đa": "Sạc đồng thời 3 thiết bị", "Đầu vào": "2 x USB-C\n1 x USB-A", "Nguồn vào": "100-240V 50/60Hz 1.8A", "Nguồn ra": "Type-C1: 5V=2A, 5V=3A, 9V=3A, 11V=4A, 12V=3A, 15V=3A, 20V=3.25A 65W Max\nType-C2: 5V=2A, 5V=3A, 9V=3A, 11V=3A, 12V=2.5A 33W Max\nUSB-A: 5V=2A, 5V=3A, 9V=2A, 10V=2.25A, 12V=1.5A 22.5W (SCP)/ 18W Max (QC)\nType-C1+Type-C2: 45W + 20W\nType-C1+USB-A: 45W + 18W\nType-C2+USB-A: 5V=4A 20W Max\nType-C1+(Type-C2+USB-A): 45W + (5V=3A) Max"}, "Công nghệ và tiện ích": {"Tiện ích": "Sạc siêu nhanh\nThiết kế gấp gọn\nChế độ dòng điện thấp thông minh\nBảo vệ quá áp\nBảo vệ quá áp dòng đầu vào\nBảo vệ quá dòng đầu ra\nNhiễu gợn sóng thấp\nBảo vệ ngắn mạch\nBảo vệ quá nhiệt\nNhiễu điện từ thấp\nChống tĩnh điện\nCó thể gập chân sạc", "Công nghệ/Đạt chứng nhận": "Công nghệ GaN III\nTương thích phổ biến với QC, SCP"}, "Thiết kế và trọng lượng": {"Chiều dài dây": "1.5 m", "Kích thước": "5.3 x 5.39 cm (Ngang x dài)"}, "Thông tin hãng": {"Hãng sản xuất": "Cuktech"}}', N'Kèm Cáp', N'https://cellphones.com.vn/media/catalog/product/c/u/cu-sac-cuktech-gan-2c1a-65w-kem-cap-c-c-1-5m-ad653c_1__1.png', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR382', 'PROD199', N'Đen', 990000.00, 73, N'{"Tổng quan": {"Công suất sạc": "140W", "Sử dụng tối đa": "4 thiết bị", "Đầu vào": "AC", "Đầu ra": "3 x USB-C\n1 x USB-A", "Nguồn vào": "110-240V 50/60Hz 2A", "Nguồn ra": "Cổng ra đơn\n+ USB-A: 33W (5–11V/3A, UFCS fast charging, PPS)\n+ Type-C3: 33W (5–11V/3A, PPS)\n+ Type-C2: 140W (28V/5A, MacBook Pro), 120W (20V/6A, điện thoại Xiaomi), 100W (20V/5A, laptop)\n+ Type-C1: 140W (28V/5A, MacBook Pro), 120W (20V/6A, điện thoại Xiaomi), 100W (20V/5A, laptop)\nCổng ra kép\n+ Type-C2 + Type-C1: 33W (điện thoại) + 100W (laptop)\n+ Type-C2 + Type-C1: 67W (điện thoại Xiaomi) + 67W/45W (điện thoại Samsung)\n+ Type-C3/USB-A + Type-C1/C2: 33W (điện thoại) + 100W (laptop)\n+ Type-C2 + Type-C1: 45W (laptop) + 65W (laptop)\nCổng ra ba\nType-C3/USB-A + Type-C2 + Type-C1:\n+ USB-A: 5V 1.5A\n+ Type-C3: 5V 1.5A\n+ Type-C2: 45W (laptop)\n+ Type-C1: 65W (laptop)\nType-C3/USB-A + Type-C2 + Type-C1:\n+ Type-C3/USB-A: 33W (điện thoại)\n+ Type-C2: 33W (điện thoại)\n+ Type-C1: 45W (laptop) / 67W (điện thoại Xiaomi) / 45W (điện thoại Samsung)\nType-C3/USB-A + Type-C2 + Type-C1:\n+ USB-A: 5V 1.5A\n+ Type-C3: 5V 1.5A\n+ Type-C2: 100W (laptop) / 67W (điện thoại Xiaomi)\n+ Type-C1: 33W (điện thoại)\nCổng ra bốn\nType-C3 + USB-A + Type-C2 + Type-C1:\n+ USB-A + Type-C3: tổng 5V 1.5A\n+ Type-C2: 45W (laptop)\n+ Type-C1: 65W (laptop)\nType-C3 + USB-A + Type-C2 + Type-C1:\n+ USB-A: 5V 1.5A\n+ Type-C3: 5V 1.5A\n+ Type-C2: 33W (điện thoại)\n+ Type-C1: 65W (điện thoại Xiaomi)\nType-C3 + USB-A + Type-C2 + Type-C1:\n+ USB-A: 5V 1.5A\n+ Type-C3: 5V 1.5A\n+ Type-C2: 45W (laptop)\n+ Type-C1: 33W (điện thoại)"}, "Công nghệ và tiện ích": {"Tiện ích": "Sạc nhanh\nThiết kế gấp gọn\nChip GaN thế hệ thứ 3\nKiến trúc PFC+LLC\nThiết kế lưới tản nhiệt\nKeo tản nhiệt hiệu suất cao, dẫn nhiệt tốt\nIntelligent Power Regulation\nBảo vệ quá áp\nBảo vệ quá dòng đầu vào\nBảo vệ quá dòng đầu ra\nNhiễu gợn sóng thấp\nBảo vệ ngắn mạch\nBảo vệ quá nhiệt\nNhiễu điện từ thấp\nChống tĩnh điện", "Công nghệ/Đạt chứng nhận": "Công nghệ GaN, PD, PPS"}, "Thiết kế và trọng lượng": {"Kích thước": "7.99 x 6.5 x 3.2 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Cuktech"}}', N'', N'https://cellphones.com.vn/media/catalog/product/c/u/cu-sac-cuktech-gan-pd3-1-3c1a-140w-ad1404us_2__1.png', 'New', 0);
