INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR441', 'PROD237', N'', 1522000.00, 43, N'{"Thông tin hãng": {"Hãng sản xuất": "Samsung Chính hãng"}, "Thông số khác": {"Áp dụng": "Samsung Galaxy S26 Series", "Thời hạn": "+ 1 năm bảo hành tai nạn rơi vỡ - vào nước (Bao gồm tất cả các loại chất lỏng)\n+ Gia hạn thêm 1 tháng bảo hành chính hãng tính từ ngày kích hoạt bảo hành (Tổng 13 tháng)", "Điều kiện": "+ Thiết bị mới kích hoạt trong vòng 55 ngày tính từ thời điểm trên hóa đơn (có thể mua từ hệ thống CellphoneS hoặc các hệ thống bán lẻ khác)\n+ Cung cấp được hoá đơn mua hàng (đối với thiết bị mua từ hệ thống bán lẻ khác)\n+ Thiết bị bật/tắt nguồn & hoạt động bình thường như mặc định của nhà sản xuất\n+ Không có thiệt hại vật lý trên thiết bị bao gồm LCD/nắp lưng và khung viền\n+ Không có dấu hiệu vào nước/thấm nước/đọng nước bao gồm cả trên màn hình\n+ Hàng chính hãng Samsung\n+ Giá sản phẩm đã bao gồm VAT", "Chính sách": "+ Sản phẩm được thay thế linh kiện chính hãng từ Samsung\n+ Nếu thiết bị bị hư hỏng nặng (chi phí sửa chữa cao hơn hoặc bằng 85% so với giá mua ban đầu của thiết bị), khách hàng sẽ được thay thiết bị mới cùng loại và cần phải thanh toán phí đổi mới 25% giá niêm yết của thiết bị.\n+ Báo sự cố, hư hỏng cho trung tâm bảo hành Samsung trong 30 ngày để được bảo hành. (Hotline 1800-588-855, nhánh 3 từ 8h00 đến 22h30 mỗi ngày trừ ngày Tết)\n+ Khách hàng có thể bảo hành tại các Trung tâm Bảo hành Ủy quyền Samsung trên toàn cầu khi gặp sự cố rơi vỡ hoặc vào nước.", "Lưu ý": "+ Gói bảo hành sẽ chấm dứt nếu điện thoại được sửa chữa tại trung tâm bảo hành không được ủy quyền trong thời hạn hợp đồng\n+ Sửa chữa và đánh giá thiệt hại tại Trung tâm bảo hành chính hãng được Samsung ủy quyền\n+ Gói bảo hành không áp dụng cho phụ kiện đi kèm (sạc - tai nghe)\n+ Quyền lợi Samsung Care+ toàn cầu chỉ áp dụng cho sửa chữa sự cố rơi vỡ vào nước, không áp dụng cho các quyền lợi khác như: thay thế thiết bị mới, gia hạn bảo hành…"}}', N'1 năm', N'', 'New', 0);
