INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR494', 'PROD251', N'', 0.00, 84, N'{"Màn hình": {"Kích thước màn hình": "6.3 inches", "Công nghệ màn hình": "LTPO AMOLED", "Tính năng màn hình": "Độ phân giải màn hình: 1220 x 2656 pixels\nTỷ lệ 19.5:9, mật độ điểm ảnh ~464 ppi\n68 tỷ màu, 120Hz, 2160Hz PWM, Dolby Vision, HDR Vivid, HDR10+, 3500 nits (peak)", "Tần số quét": "120Hz"}, "Camera sau": {"Camera sau": "Camera góc rộng: 50 MP, f/1.7\nCamera tele: 50 MP, f/2.0\nCamera góc siêu rộng: 50 MP, f/2.4", "Quay video": "8K@30fps (HDR), 4K@30/60fps (HDR10+, 10-bit Dolby Vision HDR, 10-bit LOG), 1080p@30/60/120/240/960fps, 720p@1920fps, gyro-EIS", "Tính năng camera": "Laser AF, color spectrum sensor, Leica lens, Dual-LED dual-tone flash, HDR, panorama"}, "Camera trước": {"Camera trước": "50 MP, f/2.2", "Quay video trước": "4K@30/60fps, 1080p@30/60fps, HDR10+, gyro-EIS"}, "Vi xử lý & đồ họa": {"Chipset": "Qualcomm Snapdragon 8 Elite Gen 5 (3 nm)", "GPU": "Adreno 840"}, "Giao tiếp & kết nối": {"Công nghệ NFC": "Có", "Thẻ SIM": "2 Nano-SIM", "Hồng ngoại": "Có", "Hỗ trợ mạng": "4G", "GPS": "GPS (L1+L5), BDS (B1I+B1c+B2a), GALILEO (E1+E5a), QZSS (L1+L5), NavIC (L5), GLONASS"}, "RAM & lưu trữ": {"Dung lượng RAM": "12 GB", "Bộ nhớ trong": "512 GB"}, "Pin & công nghệ sạc": {"Pin": "7000 mAh", "Công nghệ sạc": "Sạc nhanh 100W, PD3.0, QC3+, 100W PPS\nSạc không dây 50W\nSạc ngược không dây 22.5W", "Cổng sạc": "USB Type-C"}, "Tính năng khác": {"Hệ điều hành": "Android 16, HyperOS 3.0"}, "Bộ xử lý & Đồ họa": {"Loại CPU": "8 nhân (2x4.6 GHz & 6x3.62 GHz)"}, "Kích thước & Trọng lượng": {"Kích thước": "151.1 x 71.8 x 8.1 mm", "Trọng lượng": "191 g"}, "Thiết kế & Trọng lượng": {"Chất liệu khung viền": "Nhôm"}, "Thông số khác": {"Chỉ số kháng nước, bụi": "Kháng nước & bụi chuẩn IP68", "Công nghệ âm thanh": "Loa kép stereo (Dolby Atmos 24-bit/192kHz Hi-Res & Hi-Res wireless audio Snapdragon sound"}, "Tiện ích khác": {"Cảm biến vân tay": "Cảm biến vân tay siêu âm", "Các loại cảm biến": "Cảm biến gia tốc, Cảm biến tiệm cận, Cảm biến ánh sáng, La bàn, Con quay hồi chuyển, Cảm biến áp kế", "Tính năng đặc biệt": "Hỗ trợ 5G, Sạc không dây, Bảo mật vân tay, Nhận diện khuôn mặt, Kháng nước, kháng bụi"}, "Cổng kết nối": {"Wi-Fi": "Wi-Fi 802.11 a/b/g/n/ac/6/7, dual-band hoặc tri-band, Wi-Fi Direct", "Bluetooth": "5.4, A2DP, LE, aptX HD, aptX Adaptive, LHDC 5"}}', N'', N'', 'New', 0);
