INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR525', 'PROD269', N'Đen', 12990000.00, 98, N'{"Màn hình": {"Công nghệ màn hình": "AMOLED\nLên đến 3.000 nits", "Kích thước màn hình": "1.5 inch", "Độ phân giải": "480 x 480 pixels, PPI: 322"}, "Thiết kế": {"Chất liệu mặt kính": "Kính sapphire", "Chất liệu viền": "Titanium", "Thiết kế": "Mặt tròn", "Trọng lượng": "89.2 gram (không bao gồm dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Silicone", "Bề rộng dây": "2.6 cm", "Kích thước cổ tay phù hợp": "48mm: 14.5 - 21 cm\n44mm: 14 - 20.5 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua Bluetooth", "Kháng nước": "10 ATM và hỗ trợ lặn sâu đến 45m dưới mặt nước", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Cảnh báo nhịp tim bất thường, Đo VO2 max (Đo lượng tiêu thụ oxy tối đa), Bài tập thở, Bài tập thư giãn", "Tính năng thể thao": "Chế độ thể thao: 187\nNhận diện thông minh: 25 động tác tập luyện sức mạnh, 8 động tác thể thao\nHỗ trợ chạy bộ nâng cao: Chế độ chạy theo đường đua, hiệu chỉnh quỹ đạo thông minh, người dẫn tốc ảo\nKết nối với các thiết bị tập luyện ngoại vi: Đai đo nhịp tim, Đồng hồ đo công suất chạy bộ, Đồng hồ đo công suất đạp xe, Đồng hồ đo tốc độ đạp xe, Đồng hồ đo nhịp đạp xe Huấn luyện viên thể thao: Zepp Coach Trạng thái tập luyện: PeakBeats", "Thông báo": "Tin nhắn, cuộc gọi", "Tiện ích khác": "Có định vị GPS, Chế độ luyện tập, Hiển thị thông báo điện thoại, Nghe gọi trên đồng hồ, Bấm giờ, Báo thức, Dự báo thời tiết, Xem bản đồ, Nghe gọi qua Bluetooth, Đèn pin, Loa và mic tích hợp, Quản lý tiến độ tập luyện", "Tính năng đặc biệt": "Bản đồ ngoại tuyến\nĐịnh tuyến lại tự động\nĐánh dấu các vị trí quan trọng\nNhắc bạn kiểm tra nồng độ oxy trong máu khi leo dốc\nChế độ Nhiệt độ Thấp động ngay cả khi nhiệt độ giảm xuống -30°C"}, "Cấu hình": {"Kết nối": "Kết nối: Wi-Fi 2.4GHz, Bluetooth 5.2, BLE\nĐịnh vị băng tần kép với 6 hệ thống định vị vệ tinh, ăng-ten GPS phân cực tròn", "GPS tích hợp": "GPS tích hợp sẵn trên đồng hồ", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "64GB", "Hệ điều hành": "Khác", "Tương thích": "Android 7.0 trở lên, iOS 15.0 trở lên", "Ứng dụng kết nối": "Zepp App, Đồng bộ với các ứng dụng thể dục của bên thứ ba: Strava, Relive, Runkeeper, adidas Running, komoot, TrainingPeaks, Apple Health, Google Fit, intervals.icu, Treinus", "Cảm biến": "Cảm biến sinh trắc học BioTracker 6.0 PPG (5PD + 2LED)\nCảm biến gia tốc\nCảm biến con quay hồi chuyển\nCảm biến từ trường, máy đo độ cao khí áp\nCảm biến ánh sáng môi trường\nCảm biến nhiệt độ"}, "Pin": {"Thời lượng pin": "Sử dụng thông thường: Lên đến 30 ngày\nSử dụng nhiều: Lên đến 15 ngày\nAOD: Lên đến 10 ngày\nGPS chính xác: Lên đến 50 giờ\nThời lượng pin tối đa của GPS: 177 giờ\nNhiệt độ thấp (GPS bật): 40 giờ\nNhiệt độ thấp (GPS tắt): 32 ngày", "Dung lượng pin": "870 mAh (giá trị định mức)"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Anh, Tiếng Trung, Tiềng Việt", "Thời gian ra mắt": "02/2026"}, "Thông tin hãng": {"Hãng sản xuất": "Amazfit"}}', N'', N'https://cellphones.com.vn/media/catalog/product/d/h/dh_1__18.png', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR526', 'PROD270', N'Xanh dương', 7990000.00, 48, N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.32 inch", "Độ phân giải": "466 × 466 pixel, PPI 352"}, "Thiết kế": {"Chất liệu mặt kính": "Kính Côn Luân thế hệ thứ 2", "Chất liệu viền": "Hợp kim titanium", "Thiết kế": "Mặt tròn", "Trọng lượng": "34.5 g (không bao gồm dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Vải", "Kích thước cổ tay phù hợp": "Từ 12 - 19 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua Bluetooth", "Kháng nước": "5 ATM, IP69\nLặn (Độ sâu tối đa 40 mét)", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Phát hiện té ngã, Cảnh báo nhịp tim bất thường, Đo điện tâm đồ, Theo dõi chu kỳ, Tình trạng HRV (Heart Rate Variability)", "Tính năng thể thao": "Hơn 100 chế độ thể thao\nTừ đạp xe và bơi lội đến nhảy dây\nChạy đường mòn\nGolf\nLặn tự do\nChế độ xe lăn\nĐạp xe nâng cao với FTP và công suất ảo\nChạy địa hình với tốc độ điều chỉnh độ dốc\nBản đồ hơn 17.000 sân golf trên toàn thế giới, hơn 3.000 sân tại Anh", "Thông báo": "Tin nhắn, cuộc gọi, ứng dụng", "Tiện ích khác": "Có định vị GPS, Phát nhạc trên đồng hồ, Chế độ luyện tập, Hiển thị thông báo điện thoại, Nghe gọi trên đồng hồ, Nhận thông báo cuộc gọi, Loa và mic tích hợp, Quản lý tiến độ tập luyện", "Tính năng đặc biệt": "Chế độ Marathon thông minh\nTrợ lý sự kiện\nDự đoán hiếu suất tập luyện\nPhân tích ECG"}, "Cấu hình": {"Kết nối": "NFC\nBluetooth Tần số 2.4 GHz, hỗ trợ Bluetooth 6.0 và Bluetooth + BLE\nGPS (Băng tần kép L1 + L5)/GLONASS/BeiDou (Ba băng tần B1I + B1C + B2a)/GALILEO (Băng tần kép E1 + E5a)/QZSS (Băng tần kép L1 + L5)/NavIC", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "Khác", "Tương thích": "Android 9.0 trở lên\niOS 13.0 trở lên", "Ứng dụng kết nối": "HUAWEI Health", "Cảm biến": "Cảm biến gia tốc, cảm biến con quay hồi chuyển, cảm biến từ kế, cảm biến nhịp tim quang học, cảm biến áp suất khí quyển, cảm biến nhiệt độ, cảm biến ánh sáng môi trường, cảm biến điện tâm đồ, cảm biến độ sâu"}, "Pin": {"Thời lượng pin": "Pin có thể sử dụng được đến 14 ngày nếu dùng ít, 7 ngày nếu dùng thông thường, hoặc 32 giờ ở chế độ tập luyện ngoài trời", "Cổng sạc": "Sạc không dây"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Anh, Tiếng Trung, Tiếng Việt", "Thời gian ra mắt": "03/2026", "Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Huawei"}}', N'', N'https://cellphones.com.vn/media/catalog/product/d/h/dh_10__10.png', 'New', 0);
