INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR529', 'PROD271', N'Tím', 14990000.00, 72, N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.43 inch", "Độ phân giải": "466 x 466 pixels"}, "Thiết kế": {"Chất liệu mặt kính": "Sapphire", "Chất liệu viền": "Titanium", "Đường kính mặt": "49 mm", "Thiết kế": "Mặt tròn", "Trọng lượng": "69 gram"}, "Dây đeo": {"Chất liệu dây": "Silicone", "Độ dài dây": "Không công bố", "Bề rộng dây": "2.2 cm", "Kích thước cổ tay phù hợp": "Từ 12.5- 17.5 cm (dây đeo phụ kiện - 21.5 cm)", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Không", "Kháng nước": "10 ATM", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Đo VO2 max (Đo lượng tiêu thụ oxy tối đa), Tình trạng HRV (Heart Rate Variability)", "Tính năng thể thao": "Bơi lội, đạp xe, chạy bộ\nHơn 95 chế độ thể thao được cài đặt sẵn trên đồng hồ\nLặn tự do 10 m", "Thông báo": "Hiển thị thông báo điện thoại", "Tiện ích khác": "Có định vị GPS, Chế độ luyện tập, Hiển thị thông báo điện thoại, Màn hình luôn hiển thị, Tùy chỉnh mặt đồng hồ, Điều khiển chơi nhạc, Bấm giờ, Báo thức, Dự báo thời tiết, Xem bản đồ", "Tính năng đặc biệt": "Nhắc nhở sạc thông minh\nBản đồ địa hình ngoài trời và bản đồ vệ tinh\nBản đồ nhiệt toàn cầu cho 20 môn thể thao\nChia sẻ bài tập lên mạng xã hội\nĐánh giá và bình luận về bài tập\nBản đồ ngoại tuyến miễn phí\nHuấn luyện viên AI"}, "Cấu hình": {"Kết nối": "Định vị GPS, GLONASS, GALILEO, QZSS, BEIDOU\nBăng tần kép (L1+L5)\nHệ thống vệ tinh đồng thời: 4\nSố lượng vệ tinh kết nối tối đa: 32", "GPS tích hợp": "GPS tích hợp sẵn trên đồng hồ", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "32GB", "Hệ điều hành": "Khác", "Tương thích": "Android, iOS\nKhả năng tương thích với đai đo nhịp tim", "Ứng dụng kết nối": "Suunto, SuuntoPlus, Strava,...", "Cảm biến": "La bàn kỹ thuật số"}, "Pin": {"Thời lượng pin": "Chế độ đồng hồ thông minh: 16 ngày\nChỉ ở chế độ chờ: 26 ngày\nChế độ GNSS toàn hệ thống + Đa ​​băng tần: 50 giờ\nChế độ GNSS toàn hệ thống + Băng tần đơn: 65 giờ\nCác chế độ GNSS tiết kiệm năng lượng: 200 giờ", "Thời gian sạc": "Không công bố", "Dung lượng pin": "pin lithium-ion có thể sạc lại"}, "Thông tin khác": {"Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Suunto"}}', N'', N'https://cellphones.com.vn/media/catalog/product/d/h/dh_9__8.png', 'New', 0);
