INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR531', 'PROD272', N'Xám', 5990000.00, 6, N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.32 inch", "Độ phân giải": "466 x 466 pixels"}, "Thiết kế": {"Chất liệu mặt kính": "Kính Gorilla Glass chống va đập", "Chất liệu viền": "Thép", "Đường kính mặt": "Không công bố", "Thiết kế": "Mặt tròn", "Trọng lượng": "36 gram"}, "Dây đeo": {"Chất liệu dây": "Nylon", "Độ dài dây": "Không công bố", "Bề rộng dây": "2.2 cm", "Kích thước cổ tay phù hợp": "Từ 12.5 - 17.5 cm (dây đeo phụ kiện -21.5 cm)", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Không", "Kháng nước": "5ATM", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Đo VO2 max (Đo lượng tiêu thụ oxy tối đa), Tình trạng HRV (Heart Rate Variability), Bài tập thư giãn", "Tính năng thể thao": "34 bộ môn khác nhau: từ trekking, đạp xe, leo núi, yoga, tennis, boxing,... cho đến những thử thách chạy bộ ở mọi cấp độ, từ chạy giải trí, bán marathon cho đến chạy địa hình khắc nghiệt", "Thông báo": "Thông báo điện thoại", "Tiện ích khác": "Có định vị GPS, Phát nhạc trên đồng hồ, Chế độ luyện tập, Hiển thị thông báo điện thoại, Màn hình luôn hiển thị, Tùy chỉnh mặt đồng hồ, Điều khiển chơi nhạc, Bấm giờ, Dự báo thời tiết, Xem bản đồ, Trả lời nhanh tin nhắn có sẵn", "Tính năng đặc biệt": "Đo cường độ vận động, điểm căng thẳng luyện tập (TSS) và hiển thị các chỉ số CTL, TSB, TSS\nNhắc nhở sạc thông minh\nĐộ cao khí áp\nHỗ trợ POD cho bàn chân\nGửi các câu trả lời được định sẵn cho các tin nhắn đến từ đồng hồ (Chỉ dành cho Android)"}, "Cấu hình": {"Kết nối": "Định vị GPS, GLONASS, GALILEO, QZSS, BEIDOU, Băng tần kép (L1+L5)", "GPS tích hợp": "GPS tích hợp sẵn trên đồng hồ", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "4GB", "Hệ điều hành": "Khác", "Tương thích": "Android, iOS", "Ứng dụng kết nối": "Suunto, Strava, TrainingPeaks và nhiều ứng dụng khác", "Cảm biến": "La bàn"}, "Pin": {"Thời lượng pin": "Chế độ thông minh: 12 ngày\nChỉ chế độ chờ: 20 ngày\nChế độ GNSS toàn hệ thống + Đa ​​băng tần: 20 giờ\nChế độ GNSS toàn hệ thống + Đơn băng tần: 30 giờ\nTất cả các chế độ: 20 giờ / 30 giờ / 40 giờ\nChế độ GNSS tiết kiệm điện: 40 giờ", "Thời gian sạc": "Không công bố", "Dung lượng pin": "Pin lithium-ion có thể sạc lại"}, "Thông tin khác": {"Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Suunto"}}', N'', N'https://cellphones.com.vn/media/catalog/product/t/e/text_ng_n_6__7_33.png', 'New', 0);
