INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR535', 'PROD273', N'Xanh lá', 8990000.00, 25, N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.54 inch", "Độ phân giải": "480 × 480 pixels | 312 PPI\nĐộ sáng 1500 nits"}, "Thiết kế": {"Chất liệu mặt kính": "Sapphire nhân tạo", "Chất liệu viền": "Thép", "Thiết kế": "Mặt tròn", "Trọng lượng": "Khoảng 56 gram (không bao gồm dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Cao Su", "Kích thước cổ tay phù hợp": "Từ 13.5 – 20.5 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua Bluetooth", "Kháng nước": "5 ATM", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Phát hiện té ngã, Cảnh báo nhịp tim bất thường, Đo điện tâm đồ, Theo dõi chu kỳ, Bài tập thở, Bài tập thư giãn", "Tính năng thể thao": "Hơn 150 chế độ luyện tập\nTập luyện phòng gym\nTự động nhận diện bắt đầu luyện tập\nPhát hiện té ngã khi trượt tuyết\nHiển thị nhịp tim thời gian thực khi bơi\nTheo dõi lộ trình tập luyện\nTheo dõi mức tiêu hao năng lượng\nPhát sóng nhịp tim qua Bluetooth\nBản đồ ngoại tuyến\nNhắc nhở chỉ số hoạt động đạt chuẩn\n(Hỗ trợ: đi bộ, chạy bộ, đạp xe, máy chèo thuyền, máy elip, nhảy dây)", "Thông báo": "Cuộc gọi, tin nhắn", "Tiện ích khác": "Có định vị GPS, Cài ứng dụng, Chế độ luyện tập, Hiển thị thông báo điện thoại, Màn hình luôn hiển thị, Nghe gọi trên đồng hồ, Điều khiển chơi nhạc, Nhận thông báo cuộc gọi, Bấm giờ, Báo thức, Tìm điện thoại, Xem bản đồ, Nghe gọi qua Bluetooth, Đèn pin, Loa và mic tích hợp", "Tính năng đặc biệt": "Trợ lý giọng nói Xiao Ai\nXiaomi Super Island\nTrung tâm điều khiển trên cổ tay 2.0\nNhận diện cử chỉ chính xác\nHỗ trợ tương tác bằng cử chỉ tiện lợi"}, "Cấu hình": {"Kết nối": "Wi-Fi: Hỗ trợ (2.4GHz)\nĐịnh vị vệ tinh: Beidou, GPS, GLONASS, Galileo, QZSS\nBluetooth: Bluetooth kép BLE / BT 5.4\nNFC", "GPS tích hợp": "GPS tích hợp sẵn trên đồng hồ", "Camera": "Không", "CPU": "Kiến trúc hai chip flagship với vi xử lý hiệu năng cao Qualcomm W5\nVi xử lý tiết kiệm năng lượng Hengxuan 2800 (BES 2800)", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "Khác", "Tương thích": "Android 8.0 trở lên hoặc iOS 14.0 trở lên", "Cảm biến": "Cảm biến nhịp tim (bao gồm đo SpO₂)\nGia tốc kế\nCon quay hồi chuyển\nCảm biến địa từ\nCảm biến áp suất khí quyển\nCảm biến ánh sáng môi trường\nCảm biến ECG\nCảm biến EMG"}, "Pin": {"Thời lượng pin": "Chế độ hiệu năng\nSử dụng thông thường: 6 ngày\nSử dụng thông thường: 4 ngày\nCó AOD: 4 ngày\nChế độ tiết kiệm pin\nThời gian sử dụng dài: 18 ngày\nSử dụng thông thường: 12 ngày\nCó AOD: 7 ngày", "Dung lượng pin": "930 mAh Pin lithium-ion polymer", "Cổng sạc": "Nam châm"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Việt, tiếng Trung, tiếng Anh"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}}', N'', N'https://cellphones.com.vn/media/catalog/product/d/h/dh_19.png', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR536', 'PROD273', N'Đen', 8990000.00, 95, N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.54 inch", "Độ phân giải": "480 × 480 pixels | 312 PPI\nĐộ sáng 1500 nits"}, "Thiết kế": {"Chất liệu mặt kính": "Sapphire nhân tạo", "Chất liệu viền": "Thép", "Thiết kế": "Mặt tròn", "Trọng lượng": "Khoảng 56 gram (không bao gồm dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Cao Su", "Kích thước cổ tay phù hợp": "Từ 13.5 – 20.5 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua Bluetooth", "Kháng nước": "5 ATM", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Phát hiện té ngã, Cảnh báo nhịp tim bất thường, Đo điện tâm đồ, Theo dõi chu kỳ, Bài tập thở, Bài tập thư giãn", "Tính năng thể thao": "Hơn 150 chế độ luyện tập\nTập luyện phòng gym\nTự động nhận diện bắt đầu luyện tập\nPhát hiện té ngã khi trượt tuyết\nHiển thị nhịp tim thời gian thực khi bơi\nTheo dõi lộ trình tập luyện\nTheo dõi mức tiêu hao năng lượng\nPhát sóng nhịp tim qua Bluetooth\nBản đồ ngoại tuyến\nNhắc nhở chỉ số hoạt động đạt chuẩn\n(Hỗ trợ: đi bộ, chạy bộ, đạp xe, máy chèo thuyền, máy elip, nhảy dây)", "Thông báo": "Cuộc gọi, tin nhắn", "Tiện ích khác": "Có định vị GPS, Cài ứng dụng, Chế độ luyện tập, Hiển thị thông báo điện thoại, Màn hình luôn hiển thị, Nghe gọi trên đồng hồ, Điều khiển chơi nhạc, Nhận thông báo cuộc gọi, Bấm giờ, Báo thức, Tìm điện thoại, Xem bản đồ, Nghe gọi qua Bluetooth, Đèn pin, Loa và mic tích hợp", "Tính năng đặc biệt": "Trợ lý giọng nói Xiao Ai\nXiaomi Super Island\nTrung tâm điều khiển trên cổ tay 2.0\nNhận diện cử chỉ chính xác\nHỗ trợ tương tác bằng cử chỉ tiện lợi"}, "Cấu hình": {"Kết nối": "Wi-Fi: Hỗ trợ (2.4GHz)\nĐịnh vị vệ tinh: Beidou, GPS, GLONASS, Galileo, QZSS\nBluetooth: Bluetooth kép BLE / BT 5.4\nNFC", "GPS tích hợp": "GPS tích hợp sẵn trên đồng hồ", "Camera": "Không", "CPU": "Kiến trúc hai chip flagship với vi xử lý hiệu năng cao Qualcomm W5\nVi xử lý tiết kiệm năng lượng Hengxuan 2800 (BES 2800)", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "Khác", "Tương thích": "Android 8.0 trở lên hoặc iOS 14.0 trở lên", "Cảm biến": "Cảm biến nhịp tim (bao gồm đo SpO₂)\nGia tốc kế\nCon quay hồi chuyển\nCảm biến địa từ\nCảm biến áp suất khí quyển\nCảm biến ánh sáng môi trường\nCảm biến ECG\nCảm biến EMG"}, "Pin": {"Thời lượng pin": "Chế độ hiệu năng\nSử dụng thông thường: 6 ngày\nSử dụng thông thường: 4 ngày\nCó AOD: 4 ngày\nChế độ tiết kiệm pin\nThời gian sử dụng dài: 18 ngày\nSử dụng thông thường: 12 ngày\nCó AOD: 7 ngày", "Dung lượng pin": "930 mAh Pin lithium-ion polymer", "Cổng sạc": "Nam châm"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Việt, tiếng Trung, tiếng Anh"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}}', N'', N'https://cellphones.com.vn/media/catalog/product/d/h/dh_14__4.png', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR537', 'PROD274', N'Đen', 0.00, 11, N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.48 inch", "Độ phân giải": "480 x 480 pixel, độ sáng 2500 nits,"}, "Thiết kế": {"Chất liệu mặt kính": "Kính cường lực", "Chất liệu viền": "Thép", "Đường kính mặt": "46mm", "Thiết kế": "Mặt tròn", "Trọng lượng": "45.6 gram (không bao gồm dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Cao Su", "Kích thước cổ tay phù hợp": "Từ 14 – 21 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua Bluetooth", "Kháng nước": "5 ATM", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Phát hiện té ngã, Cảnh báo nhịp tim bất thường, Theo dõi chu kỳ, Bài tập thở, Bài tập thư giãn, Phát hiện chứng ngưng thở khi ngủ", "Tính năng thể thao": "Hơn 150 chế độ thể thao\nTự động nhận diện bắt đầu bài tập\nChế độ ghi Vlog thể thao\nKết nối bộ đo sức khỏe của bên thứ ba\nPhát hiện té ngã khi trượt tuyết\nNhận diện tư thế chạy\nTheo dõi hành trình (track)\nTính toán năng lượng tiêu hao\nNhắc đạt chỉ số vận động (ví dụ cho đi bộ, chạy, đạp, máy chèo, máy elip, nhảy dây)", "Thông báo": "Thông báo cuộc goi, tin nhắn, gọi xe, giao hàng, đồ ăn (taxi, giao đồ ăn, giao hàng)", "Tiện ích khác": "Có định vị GPS, Chế độ luyện tập, Hiển thị thông báo điện thoại, Tùy chỉnh mặt đồng hồ, Nghe gọi trên đồng hồ, Nhận thông báo cuộc gọi, Bấm giờ, Báo thức, Dự báo thời tiết, Xem bản đồ, Nghe gọi qua Bluetooth, Đèn pin, Tìm đồng hồ, Loa và mic tích hợp, Trả lời nhanh tin nhắn có sẵn", "Tính năng đặc biệt": "Xiaomi Super Island: mở khoá từ xa, khởi động xe\nĐiều khiển nhà thông minh trên cổ tay\nHỗ trợ bản đồ offline\nChụp ảnh màn hình trên đồng hồ\nTrợ lý giọng nói: XiaoAI (Tiểu A)\nĐiều khiển bằng cử chỉ búng tay"}, "Cấu hình": {"Kết nối": "Hỗ trợ 5 hệ thống vệ tinh: Bắc Đẩu, GPS, GLONASS, Galileo, QZSS — thu tìm vệ tinh toàn diện với chip GNSS hai tần mới\nBluetooth BLE / BT 5.4 (hỗ trợ chế độ hai kênh)\nWi‑Fi: hỗ trợ 2.4 GHz\nNFC", "GPS tích hợp": "GPS tích hợp sẵn trên đồng hồ", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "HyperOS 3", "Tương thích": "Android 8.0 trở lên hoặc iOS 14.0 trở lên", "Ứng dụng kết nối": "Mi Fitness", "Cảm biến": "Cảm biến nhịp tim (bao gồm SpO2), cảm biến gia tốc, con quay hồi chuyển (gyroscope), cảm biến từ trường (la bàn), cảm biến áp suất khí quyển, cảm biến ánh sáng môi trường"}, "Pin": {"Thời lượng pin": "Thời lượng pin siêu dài: 21 ngày\nSử dụng thông thường: 14 ngày\nBluetooth AOD — Sử dụng thông thường: 9 ngày", "Thời gian sạc": "Không công bố", "Dung lượng pin": "815mAh", "Cổng sạc": "Nam châm"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Việt, Tiếng Anh, Tiếng Trung", "Thời gian ra mắt": "03/2026", "Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}}', N'Dây cao su', N'https://cellphones.com.vn/media/catalog/product/d/h/dhnn_2.png', 'New', 0);
