INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR649', 'PROD368', N'Đen', 0.00, 6, N'{"Bộ xử lý & Đồ họa": {"Chip AI": "194 TOPs", "Loại card đồ họa": "NVIDIA GeForce RTX 4050 6GB GDDR6 VRAM, hỗ trợ 2560 NVIDIA CUDA Cores", "Loại CPU": "Intel Core i7-14700HX (20 lõi / 28 luồng, 3.9 GHz, 5.5 GHz, 33 MB, Intel Smart Cache)"}, "Bộ nhớ RAM, Ổ cứng": {"Dung lượng RAM": "16GB", "Loại RAM": "DDR5 5600 MT/s", "Số khe ram": "2 khe (1x 16GB, Nâng cấp tối đa 96GB (cắm sẵn 16GB))", "Ổ cứng": "1TB PCIe NVMe SED SSD (2 khe SSD, nâng cấp tối đa 4 TB SSD)"}, "Màn hình": {"Tần số quét": "240Hz", "Kích thước màn hình": "16 inches", "Công nghệ màn hình": "Acer ComfyView LED-backlit TFT LCD\nGrey to Grey 3 ms by Overdrive\nNvidia Advanced Optimus\nTỷ lệ khung hình 16:10\nĐộ phủ màu DCI-P3 100%\nĐộ sáng 500nits\nGóc nhìn rộng lên đến 170 độ", "Độ phân giải màn hình": "2560 x 1600 pixels (2K)"}, "Âm thanh": {"Công nghệ âm thanh": "DTS X:Ultra Audio\nDTS Sound Unbound tích hợp\nKết xuất âm thanh sống động qua tai nghe và loa trong\nDAC SNR\nCông nghệ Acer Purified\nTương thích với Cortana bằng giọng nói\nCông nghệ Acer TrueHarmony"}, "Cổng kết nối": {"Khe đọc thẻ nhớ": "Có", "Wi-Fi": "Killer Wireless Wi-Fi 6E 1675i", "Bluetooth": "Bluetooth 5.3", "Cổng giao tiếp": "1x USB Type-C\n3x USB-A\n1x Cổng HDMI 2.1 hỗ trợ HDCP\n1x Cổng Ethernet (RJ-45)\n1x thẻ nhớ microSD (tương thích SDXC)\n1x Giắc cắm DC-in cho bộ đổi nguồn AC\n1x Giắc cắm tai nghe/loa 3.5 mm"}, "Kích thước & Trọng lượng": {"Chất liệu": "Vỏ nhựa - nắp lưng kim loại", "Kích thước": "357.78 x 278.63 x 25.95/27.85 mm (Dài x Rộng x Dày)", "Trọng lượng": "2.8 kg"}, "Tiện ích khác": {"Tính năng đặc biệt": "Wi-Fi 6"}, "Tính năng khác": {"Loại đèn bàn phím": "RGB 4 zone", "Bảo mật": "Giải pháp Firmware Trusted Platform Module (TPM)\nKhóa Kensington", "Webcam": "Video HD 720p ở tốc độ 30 khung hình/giây", "Hệ điều hành": "Windows 11 Home SL"}, "Pin & công nghệ sạc": {"Pin": "90Whr 4-cell\n230W 5.5Phy Adapter"}}', N'', N'https://cellphones.com.vn/media/catalog/product/t/e/text_ng_n_1__7_50.png', 'New', 0);
