INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR870', 'PROD517', N'Bạc', 40490000.00, 46, N'{"Bộ xử lý & Đồ họa": {"Loại card đồ họa": "GPU 10 lõi\nNeural Accelerators\nCông nghệ dò tia tốc độ cao bằng phần cứng\nNeural Engine 16 lõi\nBăng thông bộ nhớ 153GB/s", "Loại CPU": "Chip Apple M5\nCPU 10 lõi với 4 lõi siêu xử lý và 6 lõi tiết kiệm điện"}, "Bộ nhớ RAM, Ổ cứng": {"Dung lượng RAM": "16GB", "Ổ cứng": "1TB"}, "Màn hình": {"Chất liệu tấm nền": "Tấm nền IPS", "Kích thước màn hình": "15.3 inches", "Công nghệ màn hình": "Màn hình Liquid Retina\nMàn hình có đèn nền LED với công nghệ IPS\nĐộ sáng 500 nit\nHỗ trợ một tỷ màu\nDải màu rộng (P3)\nCông nghệ True Tone\nHỗ trợ lên đến hai màn hình ngoài", "Độ phân giải màn hình": "2880 x 1864 pixels"}, "Âm thanh": {"Công nghệ âm thanh": "Hệ thống âm thanh bốn loa\nHỗ trợ Âm Thanh Không Gian khi phát nhạc hoặc video với Dolby Atmos trên loa tích hợp\nÂm Thanh Không Gian với khả năng theo dõi chuyển động đầu\nDãy ba micrô phối hợp\nChế độ micrô Tách Lời Nói và Âm Phổ Rộng"}, "Cổng kết nối": {"Khe đọc thẻ nhớ": "Không", "Wi-Fi": "Wi-Fi 7 (802.11be)", "Bluetooth": "Bluetooth 6", "Cổng giao tiếp": "Cổng sạc MagSafe 3\nJack cắm tai nghe 3,5 mm\nHai cổng Thunderbolt 4 (USB-C) hỗ trợ Sạc / DisplayPort / Thunderbolt 4 (lên đến 40Gb/s) / USB 4 (lên đến 40Gb/s)"}, "Kích thước & Trọng lượng": {"Chất liệu": "Vỏ kim loại", "Chất liệu vỏ màn hình": "Nhôm", "Chất liệu vỏ trên": "Nhôm", "Chất liệu vỏ dưới": "Nhôm", "Kích thước": "1.15 x 34.04 cm x 23.76 cm (Dày x Rộng x Dài)", "Trọng lượng": "1.51 kg"}, "Tiện ích khác": {"Tính năng đặc biệt": "Bảo mật vân tay, Wi-Fi 7"}, "Tính năng khác": {"Loại đèn bàn phím": "Bàn phím Magic Keyboard có đèn nền\nCảm biến ánh sáng môi trường\nBàn di chuột Force Touch để điều khiển con trỏ chính xác và cảm ứng lực; hỗ trợ Bấm Mạnh, bộ tăng tốc, vẽ cảm ứng lực, và các thao tác Multi‑Touch", "Bảo mật": "Touch ID", "Webcam": "Camera 12MP Center Stage có hỗ trợ chế độ Desk View\nQuay video HD 1080p\nBộ xử lý tín hiệu hình ảnh tiên tiến với video điện toán", "Hệ điều hành": "macOS"}, "Pin & công nghệ sạc": {"Pin": "Pin Li-Po 66,5 watt‑giờ tích hợp\nThời gian xem video trực tuyến lên đến 18 giờ\nThời gian duyệt web trên mạng không dây lên đến 15 giờ"}}', N'10CPU - 10GPU
