INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR908', 'PROD528', N'', 1590000.00, 61, N'{"Thông số khác": {"Chipset": "AMD", "Socket": "AM4", "Kích thước": "micro-ATX", "Khe RAM tối đa": "2", "Kiểu RAM hỗ trợ": "DDR4", "Dung lượng RAM tối đa": "64GB", "Bus Ram hỗ trợ": "DDR4 4600+(OC) / 4533(OC) / 4466(OC) / 4400(OC) / 4333(OC) / 4333(OC) / 4266(OC) / 4200(OC) / 4133(OC) / 4000(OC) / 3866(OC) / 3800(OC) / 3733(OC) / 3600(OC) / 3466(OC) / 3200 / 2933 / 2667 / 2400 / 2133 ECC & không phải ECC, bộ nhớ không đệm", "Lưu trữ": "CPU:\n1 x Ultra M.2 Socket (M2_1, Key M), hỗ trợ chế độ SATA3 6.0 Gb/giây & PCIe Gen3x4 (32 Gb/giây) loại 2242/2260/2280\nChipset:\n4 x SATA3 6.0 Gb/giây Connectors", "Cổng xuất hình": "Tùy chọn đầu ra đồ họa: HDMI", "Khe PCI": "1 x Khe cắm PCI Express 3.0 x16 (PCIE2: chế độ x16)\n1 x Khe cắm PCI Express 3.0 x1\n1 x Ổ cắm M.2 dọc (Phím E) với mô-đun WiFi-802.11ac PCIe WiFi đi kèm (ở I/O phía sau)", "LAN": "PCIE x1 Gigabit LAN 10/100/1000 Mb/giây\nRealtek RTL8111H\nHỗ trợ Wake-On-LAN\nHỗ trợ Lightning/ESD Protection\nHỗ trợ Energy Efficient Ethernet 802.3az\nHỗ trợ PXE", "Âm thanh": "Âm thanh HD 7.1 CH (Bộ giải mã âm thanh Realtek ALC887/897)\nHỗ trợ bảo vệ chống sét lan truyền", "Cổng I/O ở trong": "1 x SPI TPM Header\n1 x COM Port Header\n1 x Chassis Intrusion and Speaker Header\n1 x CPU Fan Connector (4 chân)*\n2 x Chassis Fan Connectors (4 chân) (Smart Fan Speed ​​Control)**\n1 x 24 pin ATX Power Connector\n1 x 4 pin 12V Power Connector\n1 x Front Panel Audio Connectors\n2 x USB 2.0 Header (Hỗ trợ 4 cổng USB 2.0) (Hỗ trợ ESD Protection)\n1 x USB 3.2 Gen1 Header (Hỗ trợ 2 cổng USB 3.2 Gen1) (Hỗ trợ ESD Protection)", "Cổng I/O phía sau": "2 x Cổng Ăng-ten\n1 x Cổng Chuột/Bàn phím PS/2\n1 x Cổng HDMI\n2 x Cổng USB 2.0 (Hỗ trợ Bảo vệ ESD)\n4 x Cổng USB 3.2 Gen1 (Hỗ trợ Bảo vệ ESD)\n1 x Cổng LAN RJ-45 có đèn LED (Đèn LED ACT/LINK và Đèn LED SPEED)\nGiắc cắm âm thanh HD: Đầu vào đường truyền / Loa trước / Micrô", "Hệ điều hành": "Microsoft Windows 10 64-bit / 11 64-bit", "Kết nối không dây": "Intel 802.11ac WiFi Modulebr>Hỗ trợ Bluetooth 4.2 / 3.0 + High speed class II\nHỗ trợ IEEE 802.11a/b/g/n/ac\nHỗ trợ Dual-Band (2.4/5 GHz)"}, "Thông tin hãng": {"Hãng sản xuất": "ASRock"}}', N'', N'', 'New', 0);
