INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR911', 'PROD531', N'', 2990000.00, 76, N'{"Thông số khác": {"Chipset": "Intel", "Socket": "LGA 1700", "Kích thước": "ATX", "Khe RAM tối đa": "4", "Kiểu RAM hỗ trợ": "DDR4", "Dung lượng RAM tối đa": "128GB", "Bus RAM": "5333+(OC)", "Lưu trữ": "CPU:\n1 x Hyper M.2 Socket (M2_1, Key M), hỗ trợ chế độ PCIe Gen4x4 (64 Gb/giây) loại 2242/2260/2280\nChipset:\n1 x Hyper M.2 Socket (M2_2, Key M), hỗ trợ chế độ PCIe Gen4x4 (64 Gb/giây) loại 2280\n4 x Đầu nối SATA3 6.0 Gb/giây", "Cổng xuất hình": "1 x HDMI 2.1 TMDS Tương thích, hỗ trợ HDCP 2.3 và độ phân giải tối đa lên đến 4K 60Hz\n1 x DisplayPort 1.4 với DSC (nén), hỗ trợ HDCP 2.3 và độ phân giải tối đa lên đến 8K 60Hz / 5K 120Hz", "Khe PCI": "CPU:\n1 x Khe cắm PCIe 4.0 x16, hỗ trợ chế độ x16\nChipset:\n1 x Khe cắm PCIe 4.0 x16, hỗ trợ chế độ x4\n1 x Khe cắm PCIe 4.0 x1\n1 x Ổ cắm M.2, hỗ trợ mô-đun WiFi/BT PCIe WiFi loại 2230 và Intel CNVio/CNVio\nHỗ trợ AMD CrossFire", "Số cổng USB": "Chipset:\n2 x USB 3.2 Gen1 Type-C (1 phía sau, 1 phía trước)\n5 x USB 3.2 Gen1 Type-A (3 phía sau, 2 phía trước)\n6 x USB 2.0 (2 phía sau, 4 phía trước)\nTất cả các cổng USB đều hỗ trợ Bảo vệ ESD", "LAN": "2.5 Gigabit LAN 10/100/1000/2500 Mb/giây\nDragon RTL8125BG\nHỗ trợ phần mềm Dragon 2.5G LAN\nKiểm soát băng thông tự động điều chỉnh thông minh", "Âm thanh": "7.1 CH HD Audio (Realtek ALC897 Audio Codec)", "Cổng I/O ở trong": "2 x Cổng Ăng-ten\n1 x Cổng Chuột/Bàn phím PS/2\n1 x Cổng HDMI\n1 x DisplayPort 1.4\n1 x Cổng USB 3.2 Gen1 Type-C\n3 x Cổng USB 3.2 Gen1 Type-A\n2 x Cổng USB 2.0\n1 x Cổng LAN RJ-45\nGiắc cắm âm thanh HD: Đầu vào / Loa trước / Micrô", "Cổng I/O phía sau": "1 x Đầu cắm SPI TPM\n1 x Đầu cắm loa và chống xâm nhập khung máy\n1 x Đầu cắm đèn LED RGB\n3 x Đầu cắm đèn LED có thể định địa chỉ\n1 x Đầu nối quạt CPU (4 chân)\n1 x Đầu nối quạt CPU/bơm nước (4 chân) (Điều khiển tốc độ quạt thông minh)\n4 x Đầu nối quạt khung máy/bơm nước (4 chân) (Điều khiển tốc độ quạt thông minh)\n1 x Đầu nối nguồn ATX 24 chân\n1 x Đầu nối nguồn 12V 8 chân (Đầu nối nguồn mật độ cao)\n1 x Đầu nối âm thanh mặt trước\n1 x Đầu nối Thunderbolt AIC (5 chân) (Hỗ trợ Thẻ ASRock Thunderbolt 4 AIC)\n2 x Đầu cắm USB 2.0 (Hỗ trợ 4 cổng USB 2.0)\n1 x Đầu cắm USB 3.2 Gen1 (Hỗ trợ 2 cổng USB 3.2 Gen1)\n1 x Đầu cắm USB 3.2 Gen1 Type C mặt trước", "Hệ điều hành": "Microsoft Windows 10 64-bit / 11 64-bit"}, "Thông tin hãng": {"Hãng sản xuất": "ASRock"}}', N'', N'', 'New', 0);
