INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR955', 'PROD562', N'Đen', 6790000.00, 80, N'{"Thông tin chung": {"Loại máy": "Không dây", "Chức năng": "Hút bụi", "Thời gian hoạt động": "Sử dụng: 35 phút (Chế độ Eco)\nSạc: <4 giờ", "Dung tích ngăn chứa nước": "Hộc nước sạch: 780ml\nHộc nước bẩn: 700ml (Đứng) / 450ml (Ngả phẳng)", "Lực hút": "21.000 Pa", "Chế độ hút": "Eco, Tiêu chuẩn, Tối ưu", "Pin": "6 x 2.500mAh", "Công suất": "400W"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ lau nhà, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú", "Tiện ích": "Tự giặt cuộn lăn nước nóng 90°C\nTự sấy khô 90°C\nCơ chế tự làm sạch cuộn lăn và khoang máy\nThời gian hoạt động đến 35 phút (Eco)"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Thiết kế ngả phẳng 180°, thân máy mỏng 14cm dễ vệ sinh gầm thấp\nCuộn lăn tràn viền\nThanh gạt TangleCut™ chống rối tóc và lông thú\nCuộn lăn xoay 480 vòng/phút\nHệ thống hút nước bẩn ngay lập tức"}}', N'', N'https://cellphones.com.vn/media/catalog/product/m/a/may-hut-bui-cam-tay-dreame-h12-gt-1_1.jpg', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR956', 'PROD563', N'Đen', 20490000.00, 93, N'{"Thông tin chung": {"Loại máy": "Không dây", "Chức năng": "Hút bụi lau sàn", "Thời gian hoạt động": "Sử dụng 72 phút (Chế độ yên tĩnh), 20 phút (Chế độ nước nóng)\nSạc 4 giờ", "Dung tích ngăn chứa nước": "Nước sạch: 800 ml\nNước bẩn: Đứng 650ml / Nằm 480ml", "Lực hút": "22.000Pa", "Chế độ hút": "Thông minh\nHút\nTăng cường\nTùy chỉnh", "Pin": "6×5.000mAh", "Độ ồn": "≤ 78 dB", "Công suất": "400W"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ lau nhà, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Làm sạch & diệt khuẩn bằng hơi nước", "Tiện ích": "Hút bụi và lau nhà đồng thời\nLàm sạch bằng hơi nước nóng 85°C\nCảm biến thông minh nhận diện vết bẩn\nTự động điều chỉnh lực hút và lượng nước\nChống rối tóc TangleCut™\nTự làm sạch cuộn lăn sau khi sử dụng\nLàm sạch hiệu quả bụi khô và chất"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "6kg", "Kích thước": "31.8 x 38 x 119.8 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}}', N'', N'https://cellphones.com.vn/media/catalog/product/m/a/may-hut-bui-cam-tay-dreame-h16-pro-steam-1_1.jpg', 'New', 0);
