INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1269', 'PROD756', N'Titan', 1600000.00, 56, N'{"Kích thước & Trọng lượng": {"Kích thước": "Dài: 16.99 cm - Rộng: 8.43 cm - Sâu: 1.47 cm", "Trọng lượng": "59g"}, "Thông số khác": {"Dòng sản phẩm": "Samsung Galaxy S26 Ultra", "Phân loại ốp": "Chống sốc", "Tính năng": "Chống sốc, va đập, Chống trầy xước", "Tương thích": "Chống rơi: 25 ft / 7.6 m\nTiêu chuẩn: MIL-STD 810G 516.6 (5X drop test)\nChống sốc & phân tán lực tác động\nChống trầy xước, móp méo, hao mòn hằng ngày\nBảo vệ toàn diện trong môi trường khắc nghiệt\nHỗ trợ Samsung Pay\nGrip chống trượt (tay nắm viền có vân)\nNút bấm lớn, phản hồi tốt\nCắt CNC chính xác, hỗ trợ đầy đủ S Pen\nĐiểm neo dây buộc tích hợp (không kèm dây)"}, "Thông tin hãng": {"Hãng sản xuất": "UAG"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Cấu trúc 5 lớp bảo vệ (multi-layer)\nKhung giáp đặc trưng (Armor Frame)\nHoàn thiện: da cao cấp / sợi carbon\nLõi chống sốc (shock-absorbing core)\nTấm polycarbonate (PC) tăng độ cứng\nViền cao su chống va đập"}}', N'', N'https://cellphones.com.vn/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_68__1.png', 'New', 0);
