INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1272', 'PROD757', N'Cam', 2000000.00, 48, N'{"Kích thước & Trọng lượng": {"Kích thước": "Dài: 16.99 cm - Rộng: 8.43 cm - Sâu: 1.47 cm", "Trọng lượng": "59g"}, "Thông số khác": {"Dòng sản phẩm": "Samsung Galaxy S26 Ultra", "Phân loại ốp": "Chống sốc", "Tính năng": "Chống sốc, va đập, Chống trầy xước", "Tương thích": "Chống rơi: 25 ft / 7.6 m\nTiêu chuẩn: MIL-STD 810G 516.6 (5X drop test)\nHấp thụ & phân tán lực tác động mạnh\nChống trầy xước, va đập, hao mòn trong môi trường khắc nghiệt\nMô-đun nam châm tích hợp\nTương thích phụ kiện từ tính\nHỗ trợ Samsung Pay\nViền cầm nắm chống trượt (contoured grip)\nNút bấm lớn, phản hồi tốt\nCắt chính xác, hỗ trợ đầy đủ S Pen\nĐiểm neo dây buộc tích hợp (không kèm dây)"}, "Thông tin hãng": {"Hãng sản xuất": "UAG"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Cấu trúc đa lớp (multi-layer protection)\nLớp phủ Dupont™ Kevlar®: siêu nhẹ, chống mài mòn cao\nLõi chống sốc (shock-absorbing core)\nTấm polycarbonate (PC) tăng độ cứng\nViền cao su chống va đập"}}', N'', N'https://cellphones.com.vn/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_77__1.png', 'New', 0);
