INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1300', 'PROD775', N'', 13290000.00, 18, N'{"Bộ xử lý & Đồ họa": {"Loại card đồ họa": "Intel UHD Graphics", "Loại CPU": "Intel Core™ i5-13420H, 8 nhân (4P + 4E) / 12 luồng, P-core tối đa 4.6 GHz, E-core tối đa 3.4 GHz, bộ nhớ đệm 12MB Intel® Smart Cache"}, "Bộ nhớ RAM, Ổ cứng": {"Dung lượng RAM": "16GB", "Loại RAM": "DDR4 3200 MHz", "Số khe ram": "2 khe (1 khe 16GB + 1 khe trống)", "Ổ cứng": "512GB M.2 2280 PCIe® 4.0 x4 NVMe® Opal 2.0"}, "Âm thanh": {"Công nghệ âm thanh": "Âm thanh HD, codec Realtek® ALC256"}, "Cổng kết nối": {"Khe đọc thẻ nhớ": "Không", "Wi-Fi": "Intel® Wi-Fi® 6 AX201, 802.11ax 2×2\nLAN tích hợp 100/1000M", "Bluetooth": "Bluetooth 5.2", "Cổng giao tiếp": "Cổng phía trước:\n\n1× USB-C® 3.2 Gen 2 (truyền dữ liệu + sạc 5V-0.9A)\n1× USB 3.2 Gen 2 (Always On + sạc 5V-2.1A)\n1× jack tai nghe/mic 3.5 mm\n\nCổng phía sau:\n\n2× USB 2.0\n2× USB 3.2 Gen 2\n1× HDMI® 2.1 TMDS\n1× DisplayP"}, "Tiện ích khác": {"Tính năng đặc biệt": "Wi-Fi 6"}, "Tính năng khác": {"Bảo mật": "Firmware TPM 2.0 tích hợp trong SoC", "Hệ điều hành": "Windows 11 Home SL"}, "Thông số khác": {"Hãng sản xuất": "Lenovo"}, "Kích thước & Trọng lượng": {"Kích thước": "179 x 182.9 x 36.5 mm", "Trọng lượng": "1.11 kg"}}', N'', N'', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1301', 'PROD776', N'', 3990000.00, 88, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Trọn bộ phiên bản cao cấp của Word, Excel, PowerPoint, OneNote và Outlook\nCông cụ Publisher và Access chỉ có trên PC\nSở hữu các tính năng và chức năng mới nhất với các phiên bản được cài đặt đầy đủ và luôn cập nhật của Outlook, Word, Excel, PowerPoi", "Tính năng nâng cao": "1TB lưu trữ đám mây OneDrive\nDễ dàng tạo các báo cáo, bản trình bày, bản tin, nội dung đào tạo cùng nhiều nội dung khác trên nền tảng web\nSở hữu email cấp doanh nghiệp với Outlook bao gồm hộp thư 50 GB/người dùng và gửi tệp đính kèm có dung lượng tố", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}}', N'', N'', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1302', 'PROD777', N'', 0.00, 76, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Phiên bản trên web của Word, Excel và PowerPoint (không tích hợp phiên bản trên máy tính của các ứng dụng)\nCập nhật và gắn kết tổ chức của bạn, cũng như kết nối mọi người với nội dung, kiến thức và các quy trình bằng site nhóm thông qua SharePoint.", "Tính năng nâng cao": "- 1TB lưu trữ đám mây OneDrive\nBookings bao gồm lịch đặt trước dựa trên web và tích hợp với Outlook\nSở hữu email cấp doanh nghiệp với Outlook bao gồm hộp thư 50 GB/người dùng và gửi tệp đính kèm có dung lượng tối đa 150 MB.", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}}', N'', N'', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1303', 'PROD778', N'', 0.00, 37, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Trọn bộ phiên bản cao cấp của Word, Excel, PowerPoint, OneNote và Outlook\nCông cụ Publisher và Access chỉ có trên PC\nTruy nhập ngay tất cả bao gồm trò chuyện, nội dung, công cụ và mọi người với Microsoft Teams.", "Tính năng nâng cao": "1TB lưu trữ đám mây OneDrive\nTăng cường bảo vệ trước các mối đe dọa trên mạng, chống virus và tấn công lừa đảo qua mạng\nSở hữu email cấp doanh nghiệp với Outlook bao gồm hộp thư 50 GB/người dùng và gửi tệp đính kèm có dung lượng tối đa 150 MB.", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}, "Tiện ích": {"Tính năng khác": "Nhận hơn 10 ứng dụng bổ sung cho nhu cầu kinh doanh của bạn (bao gồm Microsoft Loop, Clipchamp, Bookings, Planner và Forms)\nSở hữu email doanh nghiệp tùy chỉnh (ten@yourbusiness.com) với Outlook."}}', N'', N'', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1304', 'PROD779', N'', 0.00, 98, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Trọn bộ phiên bản cao cấp của Word, Excel, PowerPoint, OneNote và Outlook\nCông cụ Publisher và Access chỉ có trên PC\nTruy nhập ngay tất cả bao gồm trò chuyện, nội dung, công cụ và mọi người với Microsoft Teams.", "Tính năng nâng cao": "- 1TB lưu trữ đám mây OneDrive\nTạo hub dành cho làm việc nhóm với Microsoft Teams\nSở hữu email cấp doanh nghiệp với Outlook bao gồm hộp thư 50 GB/người dùng và gửi tệp đính kèm có dung lượng tối đa 150 MB.", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}, "Tiện ích": {"Tính năng khác": "Nhận hơn 10 ứng dụng bổ sung cho nhu cầu kinh doanh của bạn (bao gồm Microsoft Loop, Clipchamp, Bookings, Planner và Forms)\nSở hữu email doanh nghiệp tùy chỉnh (ten@yourbusiness.com) với Outlook."}}', N'', N'', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1305', 'PROD780', N'', 0.00, 57, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Trọn bộ phiên bản cơ bản của Word, Excel, PowerPoint, OneNote và Outlook\nChia sẻ cũng như quản lý nội dung, kiến thức và các ứng dụng thông qua dung lượng lưu trữ SharePoint.", "Tính năng nâng cao": "5TB lưu trữ đám mây OneDrive\nGiao diện người dùng đa ngữ cho các ứng dụng Microsoft 365", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}, "Tiện ích": {"Tính năng khác": "Làm việc thông minh hơn với 100 GB dung lượng lưu trữ email và khả năng lập lịch cấp doanh nghiệp\nGiúp bảo vệ thông tin bằng tính năng mã hóa thư Microsoft 365 cơ bản và Ngăn mất dữ liệu Microsoft 365 (cho email cũng như tệp)."}}', N'', N'', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1306', 'PROD781', N'', 0.00, 1, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Trọn bộ phiên bản của Word, Excel, PowerPoint, OneNote và Microsoft Access\nChia sẻ cũng như quản lý nội dung, kiến thức và các ứng dụng thông qua dung lượng lưu trữ SharePoint.", "Tính năng nâng cao": "5TB lưu trữ đám mây OneDrive\nGiao diện người dùng đa ngữ cho các ứng dụng Microsoft 365", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}, "Tiện ích": {"Tính năng khác": "Power BI Pro Cung cấp thông tin chuyên sâu để đưa ra các quyết định đủ thông tin, nhanh chóng với tính năng phân tích doanh nghiệp\nGiúp bảo vệ tổ chức của bạn trước các cuộc tấn công tinh vi, chẳng hạn như lừa đảo qua mạng và phần mềm độc hại gây lỗ hổ"}}', N'', N'', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1307', 'PROD782', N'', 0.00, 90, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Trải nghiệm chỉ đọc trên Word, Excel, PowerPoint và OneNote.\nMicrosoft Planner sắp xếp công việc nhóm, tạo kế hoạch mới, giao nhiệm vụ, chia sẻ tệp, trò chuyện và nhận thông tin cập nhật về tiến độ.", "Tính năng nâng cao": "2GB lưu trữ đám mây OneDrive\nMicrosoft Advanced Threat Analytics giảm rủi ro gây hư hại và nhận thông tin ở dạng xem ngắn gọn, theo thời gian thực về đường thời gian của cuộc tấn công.", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS", "Tiện ích": "Giám sát vị thế tuân thủ tổng thể, đánh giá các hành động được đề xuất và đặt cấu hình cho cài đặt nhằm đáp ứng các nghĩa vụ tuân thủ phức tạp"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}, "Tiện ích": {"Tính năng khác": "SharePoint Kiosk chia sẻ và quản lý nội dung, kiến thức cũng như các ứng dụng hỗ trợ cho hoạt động làm việc nhóm\nExchange làm việc thông minh hơn với email cấp doanh nghiệp và khả năng lập lịch"}}', N'', N'', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1308', 'PROD783', N'', 0.00, 5, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Trọn bộ phiên bản của Word, Excel, PowerPoint, Outlook và OneNote và Microsoft Teams\nMicrosoft Planner sắp xếp công việc nhóm, tạo kế hoạch mới, giao nhiệm vụ, chia sẻ tệp, trò chuyện và nhận thông tin cập nhật về tiến độ.", "Tính năng nâng cao": "2GB lưu trữ đám mây OneDrive\nMicrosoft Advanced Threat Analytics giảm rủi ro gây hư hại và nhận thông tin ở dạng xem ngắn gọn, theo thời gian thực về đường thời gian của cuộc tấn công.", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS", "Tiện ích": "Giám sát vị thế tuân thủ tổng thể, đánh giá các hành động được đề xuất và đặt cấu hình cho cài đặt nhằm đáp ứng các nghĩa vụ tuân thủ phức tạp"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}, "Tiện ích": {"Tính năng khác": "SharePoint Kiosk chia sẻ và quản lý nội dung, kiến thức cũng như các ứng dụng hỗ trợ cho hoạt động làm việc nhóm\nExchange làm việc thông minh hơn với email cấp doanh nghiệp và khả năng lập lịch"}}', N'', N'', 'New', 0);
