INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1310', 'PROD785', N'', 0.00, 5, N'{"Thông số khác": {"Loại phần mềm": "Microsoft 365", "Số lượng người dùng": "1", "Số lượng thiết bị": "5", "Thời hạn bản quyền": "1 năm", "Tính năng cơ bản": "Microsoft 365 trên web sử dụng Outlook, Word, Excel, PowerPoint và OneNote để tạo, chia sẻ và cộng tác từ mọi nơi.\nChia sẻ cũng như quản lý nội dung, kiến thức và các ứng dụng thông qua dung lượng lưu trữ SharePoint.", "Tính năng nâng cao": "1TB lưu trữ đám mây OneDrive\nĐồng bộ Active Directory tại chỗ cho tính năng đăng nhập một lần (SSO)", "Key": "Vật lý", "Hỗ trợ hệ điều hành": "Windows\nMacOS\nAndroid\niOS"}, "Thông tin hãng": {"Hãng sản xuất": "Microsoft"}, "Tiện ích": {"Tính năng khác": "Sway nhanh chóng tạo nên những bản trình bày, bản tin và tài liệu ấn tượng trực quan.\nMicrosoft 365 Copilot hợp lý hóa các quy trình kinh doanh, đồng thời nâng cao năng suất và khả năng sáng tạo với trợ lý AI an toàn cho công việc​."}}', N'', N'', 'New', 0);
