INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1389', 'PROD843', N'Trắng', 14490000.00, 43, N'{"Thông tin chung": {"Chức năng": "Hút bụi", "Lực hút": "25.000Pa", "Dung tích ngăn chứa bụi": "3,2L", "Ứng dụng kết nối": "Dreamhome", "Pin": "5.200mAh"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển từ xa bằng app và giọng nói\nTTrạm dock tự động đổ rác\nKhay giặt giẻ tự làm sạch AceClean™\nThiết lập vùng cấm và tường ảo trong app\nLên lịch dọn dẹp tự động"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Trọng lượng robot hút bụi: 3,91kg\nTrọng lượng trạm sạc: 8,62kg", "Kích thước": "Kích thước robot: 35 × 35 × 9.7 cm\nKích thước trạm sạc: 45.7 × 34 × 59 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Lực hút Vormax™ 25.000Pa với 5 mức lực hút\nHút và lau 2 trong 1 với hệ thống lau xoay DuoScrub™\nMopExtend™ RoboSwing mở rộng giẻ lau\nTự nâng giẻ lau ~10.5 mm khi gặp thảm"}}', N'', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-6_1.jpg', 'New', 0);
