INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1391', 'PROD844', N'Đen', 5490000.00, 34, N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "270 ml", "Lực hút": "20.000 Pa", "Dung tích ngăn chứa bụi": "220 ml", "Ứng dụng kết nối": "Dreamhome", "Pin": "3200 mAh"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Chống rối tóc - lông thú", "Tiện ích": "Điều khiển từ xa bằng app và giọng nói\nTrang bị hệ thống điều hướng Smart Pathfinder™, giúp nhận diện vật cản và di chuyển thông minh\nTự quay về trạm sạc khi pin yếu\nTối ưu làm sạch khe hở và mép sàn"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Trọng lượng robot hút bụi: 2,55kg\nTrọng lượng trạm sạc: 0,29kg", "Kích thước": "Kích thước robot: 32.5 × 32.5 × 9.47 cm\nKích thước trạm sạc: 14.6 × 6 × 9.86 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Lực hút Vormax™ 20.000Pa làm sạch sâu\nXử lý 100%* các hạt bụi lớn\nHút và lau 2 trong 1, hỗ trợ 32 mức điều chỉnh lượng nước\nThiết lập vùng cấm lau"}}', N'', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-dreame-f20-1_1.jpg', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1392', 'PROD845', N'Trắng', 6800000.00, 41, N'{"Thông số kỹ thuật": {"Dòng điện vào": "100-240 V"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Tốc độ xoay miếng lau: 180 vòng/phút\nTrợ lý ảo Amazon Alexa, Google Assistant hay Apple Siri\nTự động nâng giẻ lau thông minh 7mm\nKhả năng vượt gờ 20mm\nLưu trữ tối đa 3 bản đồ\nĐiều hướng LiDAR và LDS\nHệ thống định vị SLAM nâng cấp"}, "Thông tin chung": {"Thời gian hoạt động": "210 phút (Chế độ im lặng - Quite Mode)\n150 phút (Chế độ tiêu chuẩn - Standard)", "Dung tích ngăn chứa nước": "Nước sạch: 2.7 L\nNước bẩn: 2.5 L", "Lực hút": "4000 Pa", "Dung tích ngăn chứa bụi": "Robot hút bụi: 450 mL", "Ứng dụng kết nối": "DreameHome", "Pin": "5200 mAh", "Khoang chứa bụi": "Khoang chứa, Túi chứa"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Robot: 3.65 Kg\nTrạm sạc: 5.72 Kg", "Kích thước": "Robot: 350 x 350 x 103.8 mm\nTrạm sạc: 340 x 430 x 440 mm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Thông số khác": {"Kết nối": "Wi-Fi IEEE 802.11b/g/n 2.4 GHz"}}', N'Bản quốc tế', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-dreame-l10-prime-2_1_2.png', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1393', 'PROD846', N'Đen', 13990000.00, 95, N'{"Thông số kỹ thuật": {"Dòng điện vào": "220-240 V"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Tự nâng giẻ lên tới 10,5 mm\nQuy trình dọn bụi không chạm tay, thời gian lên đến 75 ngày\nHệ thống dẫn đường LiDAR, camera RGB được nâng cấp\nTự động lập chu trình làm việc hiệu quả và khoa học\nTự loại bỏ bụi bẩn vào túi đựng"}, "Thông tin chung": {"Thời gian hoạt động": "260 phút (chỉ hút hoặc chỉ lau)\n180 phút (hút lau kết hợp)", "Dung tích ngăn chứa nước": "Nước sạch: 4.5 L\nNước bẩn: 4.0 L", "Lực hút": "7000 Pa", "Dung tích ngăn chứa bụi": "Robot: 350 mL\nTrạm sạc: 3.2 L", "Ứng dụng kết nối": "DreameHome", "Pin": "6400 mAh", "Độ ồn": "63 dB(A)", "Khoang chứa bụi": "Khoang chứa, Túi chứa"}, "Thiết kế & Trọng lượng": {"Kích thước": "Robot: 350 x 350 x 103,8 mm\nTrạm sạc: 606,5 x 426 x 499 mm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Thông số khác": {"Kết nối": "Wi-Fi IEEE 802.11b/g/n 2.4 GHz"}, "Cấu hình": {"Cảm biến": "Cảm biến phát hiện thảm\nCảm biến laser"}}', N'Bản quốc tế', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-dreame-bot-l20-ult_1.png', 'New', 0);
