INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1398', 'PROD849', N'Đen', 15990000.00, 49, N'{"Thông tin chung": {"Chức năng": "Hút bụi", "Thời gian hoạt động": "Khoảng ~3.5 đến ~5 giờ", "Dung tích ngăn chứa nước": "Robot: ~110 ml\nTrạm nước sạch 4L\nTrạm nước bẩn 2.2L", "Lực hút": "24.800 Pa", "Chế độ hút": "Chỉ hút bụi\nHút và lau đồng thời\nHút trước rồi lau sau", "Dung tích ngăn chứa bụi": "Robot: ~220 ml\nTúi rác trạm: ~3L", "Ứng dụng kết nối": "Ecovacs Home", "Pin": "6.400mAh", "Độ ồn": "63 - 76dB", "Công suất": "60W"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Lưu trữ một bản đồ, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Con lăn mở rộng TruEdge™ 3.0\nChổi chính chống rối AntiTangle 3.0\nPhát hiện rối\nLưu trữ thông minh AI Intelligent Hosting\nTự động nâng giẻ lau Triple Lift\nGiặt nước nóng: 40-75°C"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Robot ~5 kg\nTrạm ~7-8 kg", "Kích thước": "Kích thước Deebot: 353 × 351 × 98mm\nKích thước trạm sạc: 338 × 459 × 500mm (có đế), 338 × 276 × 500mm (không đế)"}, "Thông tin hãng": {"Hãng sản xuất": "Ecovacs"}, "Tiện ích": {"Tính năng khác": "Con lăn OZMO ROLLER 2.0\nCảnh báo mực nước thấp\nSấy khô bằng khí nóng\nTrạm sạc tự làm sạch khay giặt giẻ Easy-clean\nHệ thống cảm biến đa điểm"}}', N'T80S', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-ecovacs-t80s-omni-1_1.jpg', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1399', 'PROD850', N'Trắng', 10990000.00, 97, N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Thời gian hoạt động": "Sử dụng: 180 phút\nSạc: 4 giờ", "Dung tích ngăn chứa nước": "80ml", "Lực hút": "18,500Pa", "Dung tích ngăn chứa bụi": "330ml", "Ứng dụng kết nối": "Roborock App", "Pin": "5,200mAh", "Độ ồn": "64dB", "Công suất": "60W"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Công nghệ Reactive Tech\nCông nghệ điều hướng PreciSense LiDAR\nCảm biến thảm siêu âm\nĐiều khiển bằng giọng nói của bên thứ ba\nGiẻ lau xoay kép 200 vòng/phút\nGiặt giẻ lau bằng nước nóng 75°C"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "11.7±0.3kg", "Kích thước": "350 x 353 x 96.5mm"}, "Thông tin hãng": {"Hãng sản xuất": "Roborock"}, "Tiện ích": {"Tính năng khác": "Khóa trẻ em và quản lý chế độ làm sạch từ xa\nLưu và quản lý nhiều bản đồ tầng\nTùy chỉnh chế độ làm sạch theo từng loại sàn và thảm"}}', N'', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-10_1.jpg', 'New', 0);
