INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1401', 'PROD851', N'Đen', 22990000.00, 59, N'{"Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ tường ảo, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Làm sạch & diệt khuẩn bằng hơi nước, Lưu trữ một bản đồ, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Nhận diện thảm thông minh\nCông nghệ AdaptiLift™ nâng hạ khung gầm\nTự động gom bụi vào túi\nTạo lập bản đồ 3D\nGiặt giẻ lau bằng nước nóng lên tới 80°C\nPhát hiện bụi bẩn thông minh\nTích hợp trợ lý giọng nói thông minh"}, "Thông tin chung": {"Lực hút": "19000 Pa", "Dung tích ngăn chứa bụi": "2.5L", "Ứng dụng kết nối": "App Roborock hoặc Mi Home", "Pin": "Lithium-ion\n6400 mAh", "Độ ồn": "≤55dB", "Khoang chứa bụi": "Khoang chứa"}, "Thiết kế & Trọng lượng": {"Kích thước": "Robot hút bụi: 350 x 353 x 79.8 mm\nDock hút bụi: 488 x 475 x 381 mm"}, "Thông tin hãng": {"Hãng sản xuất": "Roborock"}, "Cấu hình": {"Cảm biến": "Công nghệ StarSight™ 2.0 kết hợp giữa laser và cảm biến kép\nCảm biến ba chiều kết hợp radar LDS và camera RGB"}}', N'', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-roborock-saros-10r_2__1.png', 'New', 0);
