INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1403', 'PROD852', N'Đen Xám', 27990000.00, 98, N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Thời gian hoạt động": "190 phút (chế độ im lặng)", "Dung tích ngăn chứa nước": "Nước sạch: 400 ml\nNước bẩn: 300ml", "Lực hút": "35.000 Pa", "Dung tích ngăn chứa bụi": "228ml", "Ứng dụng kết nối": "Roborock App", "Pin": "6.400 mAh", "Công suất": "65W"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Làm sạch & diệt khuẩn bằng hơi nước, Lưu trữ một bản đồ, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Hệ thống lau: VibraRise 5.0 – 4000 vòng/phút\nKhung gầm: AdaptLift™ 3.0 – vượt ngưỡng 4.5 cm + 4 cm\nTự động nâng giẻ: 8 mm\nTự động giặt giẻ: Nước nóng 100°C, Tự động sấy giẻ: 55°C"}, "Thông tin hãng": {"Hãng sản xuất": "Roborock"}, "Tiện ích": {"Tính năng khác": "Tránh né vật cản: Reactive AI 3.0 + VertBeam Laser\nĐiều hướng LDS: LDS nâng hạ, giữ tầm nhìn 100°"}}', N'S20 Sonic', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-roborock-saros-20-sonic-1_1.jpg', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1404', 'PROD853', N'Trắng', 11990000.00, 79, N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "Nước sạch: 4L\nNước bẩn: 4L", "Lực hút": "10.000Pa", "Chế độ hút": "Hút bụi trước khi lau\nHút bụi\nLau nhà\nHút & lau", "Ứng dụng kết nối": "Xiaomi Home", "Pin": "4800mAh", "Công suất": "55W"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Chống rối tóc - lông thú, Lưu trữ một bản đồ, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển qua app Xiaomi Home và giọng nói\nTự động đổ rác (túi dùng ~75 ngày)\nLàm sạch theo điểm\nLau xoay kép tốc độ cao 180rpm"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "3.7kg", "Kích thước": "355 × 353.5 × 93mm"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}, "Tiện ích": {"Tính năng khác": "Điều hướng laser LDS, lập bản đồ 360°\nTự động nâng khăn lau khi gặp thảm\n4 chế độ làm sạch\nChống rối tóc (lược chữ Y + chổi chống rối)"}}', N'Vacuum H50', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-1_1.jpg', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1405', 'PROD853', N'Trắng', 14990000.00, 58, N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "Nước sạch: 4L\nNước bẩn: 4L", "Lực hút": "15.000Pa", "Ứng dụng kết nối": "Xiaomi Home", "Pin": "4800mAh", "Công suất": "55W"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Lưu trữ một bản đồ, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển qua app Xiaomi Home và giọng nói\nHỗ trợ Google Assistant & Alexa\nTúi rác dùng ~75 ngày\nLau xoay kép 180rpm"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "3.9kg", "Kích thước": "355 x 353.5 x 93mm"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}, "Tiện ích": {"Tính năng khác": "Cánh tay cơ học mở rộng (chổi + mop) làm sạch sát cạnh\nĐiều hướng LDS + cảm biến ánh sáng cấu trúc 129°\nNhận diện thảm, tự nâng giẻ lau\nChống rối tóc kép (Y-comb + chổi cạnh)"}}', N'Vacuum H50 Pro', N'https://cellphones.com.vn/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-3_2.jpg', 'New', 0);
INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1406', 'PROD854', N'Đen', 1050000.00, 19, N'{"Kết nối và điều khiển": {"Loại thiết bị": "Router Wifi", "Chuẩn Wi-Fi": "Wi-Fi 6 (802.11ax)", "Băng tần sóng": "2.4GHz & 5GHz", "Cổng kết nối": "1 cổng LAN 1000Mbps\n4 cổng LAN 1000Mbps", "Kết nối và điều khiển": "App TOTOLINK ROUTER", "Nút nhấn hỗ trợ": "1 nút Mesh\n1 nút RST"}, "Khả năng phủ sóng và hiệu năng": {"Độ phủ sóng tối đa": "20 m", "Số lượng user tối đa": "100 user", "Số Ăng ten": "4 ăng ten 5dBi", "Tốc độ mạng": "573.5 Mbps (băng tần 2.4GHz)\n2402 Mbps (băng tần 5GHz)", "Công nghệ": "Cổng nghệ OFDMA\nCông nghệ TWT (Target Wake)\nCông nghệ MU-MIMO\nCông nghệ Beamforming", "Tiện ích": "Cổng nghệ OFDMA cải thiện băng thông và hiệu suất hoạt động\nCông nghệ TWT (Target Wake) tiết kiệm điện năng cho user\nCông nghệ MU-MIMO hỗ trợ nhiều thiết bị cùng lúc\nCông nghệ Beamforming cải thiện khả năng truyền tín hiệu\nHỗ trợ Easy Mesh và Roaming mọi nơi"}, "Bảo mật": {"Bảo mật": "WPA\nWPA2\nWPA/WPA2\nWPA3"}, "Kích thước và trọng lượng": {"Kích thước": "24.1 x 14.7 x 4.85 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Totolink"}}', N'', N'https://cellphones.com.vn/media/catalog/product/r/o/router-wifi-6-totolink-ax3000-x6000r-v2_1.png', 'New', 0);
