INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1417', 'PROD863', N'', 0.00, 64, N'{"Thông tin chung": {"Kích cỡ màn hình": "65 inch", "Độ phân giải": "4K", "Loại màn hình": "QLED", "Khoảng cách xem an toàn cho mắt": "55 - 65\" (khoảng 5 - 6m)", "Loại tivi": "Smart tivi, Neo QLED", "Thương hiệu": "Samsung"}, "Công nghệ hình ảnh": {"Công nghệ hình ảnh": "HDR10+\nNQ HDR+\nGóc nhìn rộng\nChế độ bảo vệ mắt\nTối ưu độ sáng HDR\nChế độ nhà làm phim\nTăng cường màu sắc Pro\nĐèn nền Quantum Mini LED\nTăng cường độ sâu hình ảnh\nLàm mờ cục bộ Mini LED cao cấp\nTăng cường chuyển động 144 Hz\nNâng cấp hình ảnh lên 4K bằng AI\nTự động nâng cấp nội dung lên HDR\nTối ưu hình ảnh cho màn hình siêu lớn\nTối ưu bằng AI / Cá nhân hóa bằng AI", "Tần số quét": "144Hz", "Chip xử lí": "NQ4 AI Gen2 Processor"}, "Công nghệ âm thanh": {"Công nghệ âm thanh": "OTS Lite\n360 Audio\nDolby Atmos\nQ-Symphony\nAdaptive Sound Pro\nActive Voice Amplifier Pro", "Tổng công suất loa": "30W"}, "Các cổng kết nối": {"Kết nối Internet": "Wi-Fi 6\n1 x LAN", "Kết nối không dây": "Bluetooth 5.3", "Cổng nhận hình ảnh, âm thanh": "4 x HDMI\n1 x HDMI eARC", "Cổng xuất âm thanh": "1 x Digital Audio Out (Optical)", "Cổng USB": "2 x USB-A"}, "Tính năng và tiện ích": {"Tính năng chơi game": "VRR\nHGiG\nHue Sync\nGame Bar\nMiniMap Zoom\nSurround Sound\nDynamic Black EQ\nGame Motion Plus\nAI Auto Game Mode\nFreeSync Premium Pro\nAuto Game Mode (ALLM)\nSuper Ultra Wide Game View", "Ứng dụng phổ biến": "YouTube\nNetflix\nGalaxy Play (Fim+)\nClip TV\nFPT Play\nMyTV\nPOPS Kids\nVieON\nSpotify\nTrình duyệt web", "Hệ điều hành": "Tizen OS", "Công nghệ chiếu hình từ điện thoại lên TV": "Google Cast\nScreen Mirroring\nAirPlay 2", "Tiện ích nổi bật": "Tìm kiếm giọng nói bằng tiếng Việt, Tích hợp trợ lí ảo Google Assistant, Điều khiển bằng giọng nói không cần remote, Chiếu hình ảnh từ điện thoại lên TV", "Ứng dụng điều khiển