INSERT INTO ProductVariant (ProductVariantID, ProductID, Color, SellingPrice, StockQuantity, Description, Version, Image, Status, IsDeleted) VALUES ('VAR1611', 'PROD968', N'Đen', 1760000.00, 40, N'{"Màn hình": {"Công nghệ màn hình": "AMOLED, 336 PPI\nĐộ sáng tối đa 1200 nits\nTần số quét 60Hz", "Kích thước màn hình": "1.74 inch", "Độ phân giải": "360 × 480 pixels"}, "Thiết kế": {"Chất liệu mặt kính": "Kính cường lực 2.5D", "Chất liệu viền": "Nhôm", "Thiết kế": "Mặt chữ nhật", "Trọng lượng": "24.5 gram (không có dây đeo)\n40.4 gram kèm dây đeo"}, "Dây đeo": {"Chất liệu dây": "Nhựa TPU", "Độ dài dây": "Không công bố", "Bề rộng dây": "Không công bố", "Kích thước cổ tay phù hợp": "Từ 13.5 - 20.5 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Không", "Kháng nước": "5 ATM", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đo mức độ stress, Theo dõi chu kỳ, Bài tập thở", "Tính năng thể thao": "Hỗ trợ hơn 150 chế độ thể thao\n15 chế độ thể thao chuyên nghiệp\n10 khóa chạy bộ trên cổ tay\n6 chế độ nhận diện chuyển động\nNhận diện tư thế bơi\nNhận dạng tư thế chạy\nHướng dẫn thư giãn khởi động 3D", "Tiện ích khác": "Có định vị GPS, Chế độ luyện tập, Điều khiển chơi nhạc, Bấm giờ, Báo thức, Tìm điện thoại, Dự báo thời tiết", "Tính năng đặc biệt": "Đèn pin\nLa bàn"}, "Cấu hình": {"Kết nối": "Bluetooth 5.4, GNSS\nBeiDou, GPS, GLONASS, Galileo, QZSS", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "Khác", "Tương thích": "Android 8.0 trở lên\niOS12 trở lên", "Ứng dụng kết nối": "Mi Fitness", "Cảm biến": "Gia tốc kế\nCon quay hồi chuyển\nLa bàn điện tử\nMáy đo nhịp tim quang học và máy đo nồng độ oxy trong máu\nCảm biến ánh sáng xung quanh"}, "Pin": {"Thời lượng pin": "Chế độ bình thường: 21 ngày\nChế độ AOD: 10 ngày\nChế độ tải nặng: 8 ngày", "Thời gian sạc": "Khoảng 75 phút", "Dung lượng pin": "350mAh", "Cổng sạc": "Từ tính"}, "Thông tin khác": {"Thời gian ra mắt": "11/2024"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}}', N'Xiaomi Mi Band 9 Pro', N'https://cellphones.com.vn/media/catalog/product/t/e/text_ng_n_1__7_27.png', 'New', 0);
